package ast
// AST is the root of a parsed .veld contract. type AST struct { ASTVersion string `json:"astVersion"` Prefix string `json:"prefix,omitempty"` // app-level route prefix (prepended to all modules) Imports []string `json:"-"` // resolved by the file loader, not serialised Models []Model `json:"models"` Modules []Module `json:"modules"` Enums []Enum `json:"enums,omitempty"` Constants []ConstantGroup `json:"constants,omitempty"` FileImports map[string][]string `json:"-"` // sourceFile → directly imported file paths }
// Enum is a named set of string constants. type Enum struct { Name string `json:"name"` Description string `json:"description,omitempty"` Values []string `json:"values"` SourceFile string `json:"-"` Line int `json:"-"` // line in source where this enum was defined }
// Model is a named data type with typed fields. type Model struct { Name string `json:"name"` Description string `json:"description,omitempty"` Extends string `json:"extends,omitempty"` // parent model name for inheritance Fields []Field `json:"fields"` SourceFile string `json:"-"` // absolute path; set by file loader, not serialised Line int `json:"-"` // line in source where this model was defined }
// Field is a single property of a Model. type Field struct { Name string `json:"name"` Type string `json:"type"` UnionTypes []string `json:"unionTypes,omitempty"` // e.g. ["DRAFT","PENDING","APPROVED"] for union fields Optional bool `json:"optional,omitempty"` IsArray bool `json:"isArray,omitempty"` IsMap bool `json:"isMap,omitempty"` // Map<string, V> MapValueType string `json:"mapValueType,omitempty"` // the V in Map<string, V> Default string `json:"default,omitempty"` // @default(value) Deprecated string `json:"deprecated,omitempty"` // @deprecated "message" Example string `json:"example,omitempty"` // @example("value") Unique bool `json:"unique,omitempty"` // @unique Index bool `json:"index,omitempty"` // @index Relation string `json:"relation,omitempty"` // @relation(ModelName) ServerSet bool `json:"serverSet,omitempty"` // @serverSet — omit from input types Line int `json:"-"` // line in source where this field was defined }
// Module groups related Actions. type Module struct { Name string `json:"name"` Description string `json:"description,omitempty"` Prefix string `json:"prefix,omitempty"` // route path prefix BaseUrl string `json:"baseUrl,omitempty"` // optional per-module base URL (overrides global) Actions []Action `json:"actions"` SourceFile string `json:"-"` // absolute path; set by file loader, not serialised Line int `json:"-"` // line in source where this module was defined }
// Action is a single API endpoint inside a Module. type Action struct { Name string `json:"name"` Description string `json:"description,omitempty"` Method string `json:"method"` Path string `json:"path"` Input string `json:"input"` InputFields []Field `json:"inputFields,omitempty"` // inline input fields (non-empty ⇒ input was declared inline) Output string `json:"output"` OutputArray bool `json:"outputArray,omitempty"` // output User[] → true OutputFields []Field `json:"outputFields,omitempty"` // inline output fields (non-empty ⇒ output was declared inline) Query string `json:"query,omitempty"` // query param model (name or synthetic) QueryFields []Field `json:"queryFields,omitempty"` // inline query fields (non-empty ⇒ query was declared inline) Headers string `json:"headers,omitempty"` // required headers model (name or synthetic) HeaderFields []Field `json:"headerFields,omitempty"` // inline header fields (non-empty ⇒ headers was declared inline) Stream string `json:"stream,omitempty"` // server→client push type for WS actions Emit string `json:"emit,omitempty"` // client→server message type for WS actions Errors []string `json:"errors,omitempty"` // typed error codes for this action ErrorStatuses map[string]int `json:"errorStatuses,omitempty"` // explicit HTTP status per error name (e.g. insufficientFunds:400) Middleware []string `json:"middleware"` Deprecated string `json:"deprecated,omitempty"` // @deprecated "message" Line int `json:"-"` // line in source where this action was defined }
// ConstantField is a single named constant with a type and a literal value. type ConstantField struct { Name string `json:"name"` Type string `json:"type"` // string, int, float, decimal, bool, uuid, date, datetime Value string `json:"value"` // always stored as the literal string (e.g. "42", "true", "hello") Line int `json:"-"` }
// ConstantGroup is a named collection of typed constants. type ConstantGroup struct { Name string `json:"name"` Description string `json:"description,omitempty"` Fields []ConstantField `json:"fields"` SourceFile string `json:"-"` Line int `json:"-"` }

