// Package diff compares two Veld ASTs and classifies every change as
// breaking or non-breaking.
//
// Breaking changes are those that require client or server code updates to stay
// correct. Non-breaking (additive) changes can be deployed without touching
// existing consumers.
//
// The diff is surfaced by "veld generate" / "veld watch" whenever a previous
// lock file (.veld.lock.json) exists alongside veld.config.json.
package diff

import (
	"fmt"
	"sort"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

// ── Change types ──────────────────────────────────────────────────────────────

// ChangeKind classifies the impact of a single contract change.
type ChangeKind int

const (
	// Breaking changes require consumers (clients or server) to update.
	Breaking ChangeKind = iota
	// Added changes are purely additive and safe to deploy without client updates.
	Added
)

// Change represents a single detected difference between two contract versions.
type Change struct {
	Kind    ChangeKind
	Path    string // human-readable location, e.g. "Users.createUser.input.email"
	Message string // concise description, e.g. `required field "email" removed`
}

func (c Change) IsBreaking() bool { return c.Kind == Breaking }

// ── Public API ────────────────────────────────────────────────────────────────

// Diff compares two ASTs and returns all detected changes sorted with breaking
// changes first, then additions, each group in alphabetical path order.
func Diff(old, new ast.AST) []Change {
	var changes []Change

	oldMods := modulesByName(old.Modules)
	newMods := modulesByName(new.Modules)

	// Removed modules — always breaking.
	for name := range oldMods {
		if _, exists := newMods[name]; !exists {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    name,
				Message: fmt.Sprintf("module %q removed", name),
			})
		}
	}

	// Added modules — non-breaking.
	for name := range newMods {
		if _, exists := oldMods[name]; !exists {
			changes = append(changes, Change{
				Kind:    Added,
				Path:    name,
				Message: fmt.Sprintf("module %q added", name),
			})
		}
	}

	// Changed modules — compare action by action.
	for name, oldMod := range oldMods {
		newMod, exists := newMods[name]
		if !exists {
			continue
		}
		changes = append(changes, diffModule(old, new, oldMod, newMod)...)
	}

	sortChanges(changes)
	return changes
}

// HasBreaking returns true if any change in the slice is breaking.
func HasBreaking(changes []Change) bool {
	for _, c := range changes {
		if c.IsBreaking() {
			return true
		}
	}
	return false
}

// ── Module diff ───────────────────────────────────────────────────────────────

func diffModule(oldAST, newAST ast.AST, old, new ast.Module) []Change {
	var changes []Change
	prefix := old.Name

	// Prefix change — clients and servers both depend on the route path.
	if old.Prefix != new.Prefix {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    prefix,
			Message: fmt.Sprintf("route prefix changed from %q to %q", old.Prefix, new.Prefix),
		})
	}

	oldActs := actionsByName(old.Actions)
	newActs := actionsByName(new.Actions)

	// Removed actions.
	for name := range oldActs {
		if _, exists := newActs[name]; !exists {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    prefix + "." + name,
				Message: fmt.Sprintf("action %q removed", name),
			})
		}
	}

	// Added actions.
	for name := range newActs {
		if _, exists := oldActs[name]; !exists {
			changes = append(changes, Change{
				Kind:    Added,
				Path:    prefix + "." + name,
				Message: fmt.Sprintf("action %q added", name),
			})
		}
	}

	// Changed actions.
	for name, oldAct := range oldActs {
		newAct, exists := newActs[name]
		if !exists {
			continue
		}
		changes = append(changes, diffAction(oldAST, newAST, prefix, name, oldAct, newAct)...)
	}

	return changes
}

// ── Action diff ───────────────────────────────────────────────────────────────

func diffAction(oldAST, newAST ast.AST, module, action string, old, new ast.Action) []Change {
	var changes []Change
	base := module + "." + action

	if old.Method != new.Method {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base,
			Message: fmt.Sprintf("HTTP method changed from %s to %s", old.Method, new.Method),
		})
	}

	if old.Path != new.Path {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base,
			Message: fmt.Sprintf("route path changed from %q to %q", old.Path, new.Path),
		})
	}

	if old.OutputArray != new.OutputArray {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base + ".output",
			Message: fmt.Sprintf("output changed: array=%v → array=%v", old.OutputArray, new.OutputArray),
		})
	}

	changes = append(changes, diffActionModel(oldAST, newAST, base+".input", old.Input, new.Input, true)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".output", old.Output, new.Output, false)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".query", old.Query, new.Query, true)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".headers", old.Headers, new.Headers, true)...)

	return changes
}

// diffActionModel handles the comparison of one model slot (input/output/query).
// isInput controls the field-level breaking-change semantics.
func diffActionModel(oldAST, newAST ast.AST, path, oldName, newName string, isInput bool) []Change {
	switch {
	case oldName == newName && oldName == "":
		return nil // both absent — no change

	case oldName == "" && newName != "":
		if isInput {
			// Adding a required input model means clients must now provide a body.
			return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("input model added (%s) — clients must now send a request body", newName)}}
		}
		return []Change{{Kind: Added, Path: path, Message: fmt.Sprintf("output model added (%s)", newName)}}

	case oldName != "" && newName == "":
		return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("model removed (was %s)", oldName)}}

	case oldName != newName:
		return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("model changed from %s to %s", oldName, newName)}}

	default:
		// Same model name — diff field-by-field.
		return diffModelFields(oldAST, newAST, path, oldName, isInput)
	}
}

// ── Model field diff ──────────────────────────────────────────────────────────

// diffModelFields compares the fields of a model used in two ASTs.
//
// Input semantics (isInput=true):
//   - Required field added   → Breaking (clients must now send it)
//   - Any field removed      → Breaking (server contract no longer accepts it)
//   - Optional field added   → Non-breaking
//   - Field type changed     → Breaking
//   - Optional→Required      → Breaking
//
// Output semantics (isInput=false):
//   - Required field removed → Breaking (clients may read it; now undefined)
//   - Any field added        → Non-breaking (clients ignore unknown fields)
//   - Field type changed     → Breaking
//   - Required→Optional      → Breaking (clients may assume it's always present)
func diffModelFields(oldAST, newAST ast.AST, path, modelName string, isInput bool) []Change {
	oldModel := findModel(oldAST, modelName)
	newModel := findModel(newAST, modelName)
	if oldModel == nil || newModel == nil {
		return nil
	}

	var changes []Change
	oldFields := fieldsByName(allFields(*oldModel, oldAST))
	newFields := fieldsByName(allFields(*newModel, newAST))

	// Removed fields.
	for name, oldF := range oldFields {
		if _, exists := newFields[name]; !exists {
			if isInput {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q removed from input model %s", name, modelName),
				})
			} else if !oldF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("required field %q removed from output model %s", name, modelName),
				})
			}
			// Optional field removed from output → non-breaking (skip silently).
		}
	}

	// Added fields.
	for name, newF := range newFields {
		if _, exists := oldFields[name]; !exists {
			if isInput && !newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("required field %q added to input model %s — clients must now send it", name, modelName),
				})
			} else {
				changes = append(changes, Change{
					Kind:    Added,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q added to model %s", name, modelName),
				})
			}
		}
	}

	// Modified fields.
	for name, oldF := range oldFields {
		newF, exists := newFields[name]
		if !exists {
			continue
		}
		if typeChanged(oldF, newF) {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    path + "." + name,
				Message: fmt.Sprintf("field %q type changed in model %s (%s → %s)", name, modelName, describeType(oldF), describeType(newF)),
			})
		}
		if oldF.Optional != newF.Optional {
			if isInput && !newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q became required in input model %s", name, modelName),
				})
			} else if !isInput && newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q became optional in output model %s — clients may have relied on it always being present", name, modelName),
				})
			}
		}
	}

	return changes
}

// ── Helpers ───────────────────────────────────────────────────────────────────

func modulesByName(mods []ast.Module) map[string]ast.Module {
	m := make(map[string]ast.Module, len(mods))
	for _, mod := range mods {
		m[mod.Name] = mod
	}
	return m
}

func actionsByName(acts []ast.Action) map[string]ast.Action {
	m := make(map[string]ast.Action, len(acts))
	for _, a := range acts {
		m[a.Name] = a
	}
	return m
}

func fieldsByName(fields []ast.Field) map[string]ast.Field {
	m := make(map[string]ast.Field, len(fields))
	for _, f := range fields {
		m[f.Name] = f
	}
	return m
}

func findModel(a ast.AST, name string) *ast.Model {
	for i := range a.Models {
		if a.Models[i].Name == name {
			return &a.Models[i]
		}
	}
	return nil
}

// allFields returns a model's own fields plus all inherited fields, deduplicated
// (child field wins on name collision — mirrors how inheritance works at runtime).
func allFields(model ast.Model, a ast.AST) []ast.Field {
	if model.Extends == "" {
		return model.Fields
	}
	parent := findModel(a, model.Extends)
	if parent == nil {
		return model.Fields
	}
	inherited := allFields(*parent, a)
	seen := make(map[string]bool, len(model.Fields))
	for _, f := range model.Fields {
		seen[f.Name] = true
	}
	out := make([]ast.Field, 0, len(inherited)+len(model.Fields))
	for _, f := range inherited {
		if !seen[f.Name] {
			out = append(out, f)
		}
	}
	return append(out, model.Fields...)
}

func typeChanged(a, b ast.Field) bool {
	return a.Type != b.Type ||
		a.IsArray != b.IsArray ||
		a.IsMap != b.IsMap ||
		a.MapValueType != b.MapValueType
}

func describeType(f ast.Field) string {
	switch {
	case f.IsMap:
		return fmt.Sprintf("Map<string,%s>", f.MapValueType)
	case f.IsArray:
		return f.Type + "[]"
	default:
		return f.Type
	}
}

// sortChanges sorts in place: breaking first (alphabetical by path), then added.
func sortChanges(changes []Change) {
	sort.SliceStable(changes, func(i, j int) bool {
		ki, kj := changes[i].Kind, changes[j].Kind
		if ki != kj {
			return ki < kj // Breaking (0) before Added (1)
		}
		return changes[i].Path < changes[j].Path
	})
}

// Package diff compares two Veld ASTs and classifies every change as
// breaking or non-breaking.
//
// Breaking changes are those that require client or server code updates to stay
// correct. Non-breaking (additive) changes can be deployed without touching
// existing consumers.
//
// The diff is surfaced by "veld generate" / "veld watch" whenever a previous
// lock file (.veld.lock.json) exists alongside veld.config.json.
package diff

import (
	"fmt"
	"sort"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

// ── Change types ──────────────────────────────────────────────────────────────

// ChangeKind classifies the impact of a single contract change.
type ChangeKind int

const (
	// Breaking changes require consumers (clients or server) to update.
	Breaking ChangeKind = iota
	// Added changes are purely additive and safe to deploy without client updates.
	Added
)

// Change represents a single detected difference between two contract versions.
type Change struct {
	Kind    ChangeKind
	Path    string // human-readable location, e.g. "Users.createUser.input.email"
	Message string // concise description, e.g. `required field "email" removed`
}

func (c Change) IsBreaking() bool { return c.Kind == Breaking }

// ── Public API ────────────────────────────────────────────────────────────────

// Diff compares two ASTs and returns all detected changes sorted with breaking
// changes first, then additions, each group in alphabetical path order.
func Diff(old, new ast.AST) []Change {
	var changes []Change

	oldMods := modulesByName(old.Modules)
	newMods := modulesByName(new.Modules)

	// Removed modules — always breaking.
	for name := range oldMods {
		if _, exists := newMods[name]; !exists {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    name,
				Message: fmt.Sprintf("module %q removed", name),
			})
		}
	}

	// Added modules — non-breaking.
	for name := range newMods {
		if _, exists := oldMods[name]; !exists {
			changes = append(changes, Change{
				Kind:    Added,
				Path:    name,
				Message: fmt.Sprintf("module %q added", name),
			})
		}
	}

	// Changed modules — compare action by action.
	for name, oldMod := range oldMods {
		newMod, exists := newMods[name]
		if !exists {
			continue
		}
		changes = append(changes, diffModule(old, new, oldMod, newMod)...)
	}

	sortChanges(changes)
	return changes
}

// HasBreaking returns true if any change in the slice is breaking.
func HasBreaking(changes []Change) bool {
	for _, c := range changes {
		if c.IsBreaking() {
			return true
		}
	}
	return false
}

// ── Module diff ───────────────────────────────────────────────────────────────

func diffModule(oldAST, newAST ast.AST, old, new ast.Module) []Change {
	var changes []Change
	prefix := old.Name

	// Prefix change — clients and servers both depend on the route path.
	if old.Prefix != new.Prefix {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    prefix,
			Message: fmt.Sprintf("route prefix changed from %q to %q", old.Prefix, new.Prefix),
		})
	}

	oldActs := actionsByName(old.Actions)
	newActs := actionsByName(new.Actions)

	// Removed actions.
	for name := range oldActs {
		if _, exists := newActs[name]; !exists {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    prefix + "." + name,
				Message: fmt.Sprintf("action %q removed", name),
			})
		}
	}

	// Added actions.
	for name := range newActs {
		if _, exists := oldActs[name]; !exists {
			changes = append(changes, Change{
				Kind:    Added,
				Path:    prefix + "." + name,
				Message: fmt.Sprintf("action %q added", name),
			})
		}
	}

	// Changed actions.
	for name, oldAct := range oldActs {
		newAct, exists := newActs[name]
		if !exists {
			continue
		}
		changes = append(changes, diffAction(oldAST, newAST, prefix, name, oldAct, newAct)...)
	}

	return changes
}

// ── Action diff ───────────────────────────────────────────────────────────────

func diffAction(oldAST, newAST ast.AST, module, action string, old, new ast.Action) []Change {
	var changes []Change
	base := module + "." + action

	if old.Method != new.Method {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base,
			Message: fmt.Sprintf("HTTP method changed from %s to %s", old.Method, new.Method),
		})
	}

	if old.Path != new.Path {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base,
			Message: fmt.Sprintf("route path changed from %q to %q", old.Path, new.Path),
		})
	}

	if old.OutputArray != new.OutputArray {
		changes = append(changes, Change{
			Kind:    Breaking,
			Path:    base + ".output",
			Message: fmt.Sprintf("output changed: array=%v → array=%v", old.OutputArray, new.OutputArray),
		})
	}

	changes = append(changes, diffActionModel(oldAST, newAST, base+".input", old.Input, new.Input, true)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".output", old.Output, new.Output, false)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".query", old.Query, new.Query, true)...)
	changes = append(changes, diffActionModel(oldAST, newAST, base+".headers", old.Headers, new.Headers, true)...)

	if old.SuccessStatus != new.SuccessStatus {
		changes = append(changes, Change{
			Kind:    Added,
			Path:    base,
			Message: fmt.Sprintf("success status changed from %d to %d", old.SuccessStatus, new.SuccessStatus),
		})
	}

	return changes
}

// diffActionModel handles the comparison of one model slot (input/output/query).
// isInput controls the field-level breaking-change semantics.
func diffActionModel(oldAST, newAST ast.AST, path, oldName, newName string, isInput bool) []Change {
	switch {
	case oldName == newName && oldName == "":
		return nil // both absent — no change

	case oldName == "" && newName != "":
		if isInput {
			// Adding a required input model means clients must now provide a body.
			return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("input model added (%s) — clients must now send a request body", newName)}}
		}
		return []Change{{Kind: Added, Path: path, Message: fmt.Sprintf("output model added (%s)", newName)}}

	case oldName != "" && newName == "":
		return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("model removed (was %s)", oldName)}}

	case oldName != newName:
		return []Change{{Kind: Breaking, Path: path, Message: fmt.Sprintf("model changed from %s to %s", oldName, newName)}}

	default:
		// Same model name — diff field-by-field.
		return diffModelFields(oldAST, newAST, path, oldName, isInput)
	}
}

// ── Model field diff ──────────────────────────────────────────────────────────

// diffModelFields compares the fields of a model used in two ASTs.
//
// Input semantics (isInput=true):
//   - Required field added   → Breaking (clients must now send it)
//   - Any field removed      → Breaking (server contract no longer accepts it)
//   - Optional field added   → Non-breaking
//   - Field type changed     → Breaking
//   - Optional→Required      → Breaking
//
// Output semantics (isInput=false):
//   - Required field removed → Breaking (clients may read it; now undefined)
//   - Any field added        → Non-breaking (clients ignore unknown fields)
//   - Field type changed     → Breaking
//   - Required→Optional      → Breaking (clients may assume it's always present)
func diffModelFields(oldAST, newAST ast.AST, path, modelName string, isInput bool) []Change {
	oldModel := findModel(oldAST, modelName)
	newModel := findModel(newAST, modelName)
	if oldModel == nil || newModel == nil {
		return nil
	}

	var changes []Change
	oldFields := fieldsByName(allFields(*oldModel, oldAST))
	newFields := fieldsByName(allFields(*newModel, newAST))

	// Removed fields.
	for name, oldF := range oldFields {
		if _, exists := newFields[name]; !exists {
			if isInput {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q removed from input model %s", name, modelName),
				})
			} else if !oldF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("required field %q removed from output model %s", name, modelName),
				})
			}
			// Optional field removed from output → non-breaking (skip silently).
		}
	}

	// Added fields.
	for name, newF := range newFields {
		if _, exists := oldFields[name]; !exists {
			if isInput && !newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("required field %q added to input model %s — clients must now send it", name, modelName),
				})
			} else {
				changes = append(changes, Change{
					Kind:    Added,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q added to model %s", name, modelName),
				})
			}
		}
	}

	// Modified fields.
	for name, oldF := range oldFields {
		newF, exists := newFields[name]
		if !exists {
			continue
		}
		if typeChanged(oldF, newF) {
			changes = append(changes, Change{
				Kind:    Breaking,
				Path:    path + "." + name,
				Message: fmt.Sprintf("field %q type changed in model %s (%s → %s)", name, modelName, describeType(oldF), describeType(newF)),
			})
		}
		if oldF.Optional != newF.Optional {
			if isInput && !newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q became required in input model %s", name, modelName),
				})
			} else if !isInput && newF.Optional {
				changes = append(changes, Change{
					Kind:    Breaking,
					Path:    path + "." + name,
					Message: fmt.Sprintf("field %q became optional in output model %s — clients may have relied on it always being present", name, modelName),
				})
			}
		}
	}

	return changes
}

// ── Helpers ───────────────────────────────────────────────────────────────────

func modulesByName(mods []ast.Module) map[string]ast.Module {
	m := make(map[string]ast.Module, len(mods))
	for _, mod := range mods {
		m[mod.Name] = mod
	}
	return m
}

func actionsByName(acts []ast.Action) map[string]ast.Action {
	m := make(map[string]ast.Action, len(acts))
	for _, a := range acts {
		m[a.Name] = a
	}
	return m
}

func fieldsByName(fields []ast.Field) map[string]ast.Field {
	m := make(map[string]ast.Field, len(fields))
	for _, f := range fields {
		m[f.Name] = f
	}
	return m
}

func findModel(a ast.AST, name string) *ast.Model {
	for i := range a.Models {
		if a.Models[i].Name == name {
			return &a.Models[i]
		}
	}
	return nil
}

// allFields returns a model's own fields plus all inherited fields, deduplicated
// (child field wins on name collision — mirrors how inheritance works at runtime).
func allFields(model ast.Model, a ast.AST) []ast.Field {
	if model.Extends == "" {
		return model.Fields
	}
	parent := findModel(a, model.Extends)
	if parent == nil {
		return model.Fields
	}
	inherited := allFields(*parent, a)
	seen := make(map[string]bool, len(model.Fields))
	for _, f := range model.Fields {
		seen[f.Name] = true
	}
	out := make([]ast.Field, 0, len(inherited)+len(model.Fields))
	for _, f := range inherited {
		if !seen[f.Name] {
			out = append(out, f)
		}
	}
	return append(out, model.Fields...)
}

func typeChanged(a, b ast.Field) bool {
	return a.Type != b.Type ||
		a.IsArray != b.IsArray ||
		a.IsMap != b.IsMap ||
		a.MapValueType != b.MapValueType
}

func describeType(f ast.Field) string {
	switch {
	case f.IsMap:
		return fmt.Sprintf("Map<string,%s>", f.MapValueType)
	case f.IsArray:
		return f.Type + "[]"
	default:
		return f.Type
	}
}

// sortChanges sorts in place: breaking first (alphabetical by path), then added.
func sortChanges(changes []Change) {
	sort.SliceStable(changes, func(i, j int) bool {
		ki, kj := changes[i].Kind, changes[j].Kind
		if ki != kj {
			return ki < kj // Breaking (0) before Added (1)
		}
		return changes[i].Path < changes[j].Path
	})
}

package docsgen

import (
	"fmt"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

// BuildHTML generates a standalone single-file HTML SPA for API documentation.
// services carries workspace grouping; pass nil for single-service mode.
func BuildHTML(a ast.AST, services []ServiceInfo) string {
	if len(services) == 0 {
		names := make([]string, len(a.Modules))
		for i, m := range a.Modules {
			names[i] = m.Name
		}
		services = []ServiceInfo{{Name: "API", ModuleNames: names}}
	}

	modelSet := make(map[string]bool, len(a.Models))
	for _, m := range a.Models {
		modelSet[m.Name] = true
	}
	enumSet := make(map[string]bool, len(a.Enums))
	for _, e := range a.Enums {
		enumSet[e.Name] = true
	}
	moduleByName := make(map[string]ast.Module, len(a.Modules))
	for _, mod := range a.Modules {
		moduleByName[mod.Name] = mod
	}

	typeChip := func(t string) string {
		if t == "" {
			return ""
		}
		isArray := strings.HasSuffix(t, "[]")
		base := strings.TrimSuffix(t, "[]")
		suffix := ""
		if isArray {
			suffix = "[]"
		}
		if modelSet[base] {
			id := "model-" + slug(base)
			return fmt.Sprintf(`<a class="type-chip" href="#%s" onclick="navigateTo('%s');return false">%s%s</a>`, id, id, esc(base), esc(suffix))
		}
		if enumSet[base] {
			id := "enum-" + slug(base)
			return fmt.Sprintf(`<a class="type-chip" href="#%s" onclick="navigateTo('%s');return false">%s%s</a>`, id, id, esc(base), esc(suffix))
		}
		return `<span class="plain-chip">` + esc(t) + `</span>`
	}

	fieldTypeChip := func(f ast.Field) string {
		if f.IsMap {
			return fmt.Sprintf(`<span class="plain-chip">Map&lt;string,&nbsp;%s&gt;</span>`, typeChip(f.MapValueType))
		}
		t := f.Type
		if f.IsArray {
			t += "[]"
		}
		return typeChip(t)
	}

	var sb strings.Builder
	sb.WriteString(htmlHead)

	// ── Sidebar ───────────────────────────────────────────────────────────────
	sb.WriteString("<nav class=\"sidebar\">\n")
	sb.WriteString("  <div class=\"sidebar-brand\">\n")
	sb.WriteString("    <div class=\"brand-name\">\n")
	sb.WriteString("      <svg class=\"brand-icon\" viewBox=\"0 0 20 20\" fill=\"none\"><path d=\"M10 2L17.3 6V14L10 18L2.7 14V6L10 2Z\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-linejoin=\"round\"/><path d=\"M10 2V18\" stroke=\"currentColor\" stroke-width=\"1\" opacity=\".4\"/><path d=\"M2.7 6L17.3 14\" stroke=\"currentColor\" stroke-width=\"1\" opacity=\".4\"/><path d=\"M17.3 6L2.7 14\" stroke=\"currentColor\" stroke-width=\"1\" opacity=\".4\"/></svg>\n")
	sb.WriteString("      API Reference\n")
	sb.WriteString("    </div>\n")
	sb.WriteString("    <div class=\"brand-sub\">Generated by Veld</div>\n")
	sb.WriteString("  </div>\n")
	sb.WriteString("  <div class=\"search-wrap\">\n")
	sb.WriteString("    <div class=\"search-inner\">\n")
	sb.WriteString("      <svg class=\"search-icon-svg\" width=\"13\" height=\"13\" viewBox=\"0 0 14 14\" fill=\"none\"><circle cx=\"6\" cy=\"6\" r=\"4.5\" stroke=\"currentColor\" stroke-width=\"1.5\"/><line x1=\"9.5\" y1=\"9.5\" x2=\"12.5\" y2=\"12.5\" stroke=\"currentColor\" stroke-width=\"1.5\" stroke-linecap=\"round\"/></svg>\n")
	sb.WriteString("      <input type=\"text\" id=\"nav-search\" placeholder=\"Search endpoints, models\u2026\" autocomplete=\"off\" oninput=\"filterNav(this.value)\">\n")
	sb.WriteString("      <kbd class=\"search-hint\">/</kbd>\n")
	sb.WriteString("    </div>\n")
	sb.WriteString("  </div>\n")
	sb.WriteString("  <div class=\"nav-tree\">\n")

	multiService := len(services) > 1

	for _, svc := range services {
		svcSlug := slug(svc.Name)
		sb.WriteString(fmt.Sprintf("    <div class=\"nav-svc\" id=\"nav-svc-%s\">\n", svcSlug))
		if multiService {
			sb.WriteString(fmt.Sprintf("      <div class=\"nav-svc-label\" onclick=\"toggleSvc(this)\"><span>%s</span><span class=\"nav-toggle\">\u25be</span></div>\n", esc(svc.Name)))
		}
		sb.WriteString("      <div class=\"nav-svc-body\">\n")

		for _, mn := range svc.ModuleNames {
			mod, ok := moduleByName[mn]
			if !ok {
				continue
			}
			modSlug := slug(mn)
			sb.WriteString("        <div class=\"nav-mod\">\n")
			sb.WriteString(fmt.Sprintf("          <div class=\"nav-mod-label\" onclick=\"toggleMod(this)\"><span>%s</span><span class=\"nav-badge\">%d</span></div>\n", esc(mod.Name), len(mod.Actions)))
			sb.WriteString("          <div class=\"nav-mod-body\">\n")

			for _, act := range mod.Actions {
				actID := fmt.Sprintf("action-%s-%s-%s", svcSlug, modSlug, slug(act.Name))
				method := strings.ToUpper(act.Method)
				search := strings.ToLower(act.Name) + " " + strings.ToLower(method) + " " + strings.ToLower(act.Path)
				sb.WriteString(fmt.Sprintf("            <a class=\"nav-ep\" href=\"#%s\" data-target=\"%s\" data-search=\"%s\" onclick=\"navigateTo('%s');return false;\">\n",
					actID, actID, esc(search), actID))
				sb.WriteString(fmt.Sprintf("              <span class=\"nav-method nav-method-%s\">%s</span>\n", method, method))
				sb.WriteString(fmt.Sprintf("              <span class=\"nav-ep-name\">%s</span>\n", esc(act.Name)))
				sb.WriteString("            </a>\n")
			}

			sb.WriteString("          </div>\n        </div>\n")
		}

		sb.WriteString("      </div>\n    </div>\n")
	}

	if len(a.Models) > 0 {
		sb.WriteString("    <div class=\"nav-group\">\n")
		sb.WriteString(fmt.Sprintf("      <div class=\"nav-group-label\" onclick=\"toggleGroup(this)\">Models <span class=\"nav-badge\">%d</span></div>\n", len(a.Models)))
		sb.WriteString("      <div class=\"nav-group-body\">\n")
		for _, m := range a.Models {
			id := "model-" + slug(m.Name)
			sb.WriteString(fmt.Sprintf("        <a class=\"nav-type\" href=\"#%s\" data-target=\"%s\" data-search=\"%s\" onclick=\"navigateTo('%s');return false;\">%s</a>\n",
				id, id, strings.ToLower(m.Name), id, esc(m.Name)))
		}
		sb.WriteString("      </div>\n    </div>\n")
	}

	if len(a.Enums) > 0 {
		sb.WriteString("    <div class=\"nav-group\">\n")
		sb.WriteString(fmt.Sprintf("      <div class=\"nav-group-label\" onclick=\"toggleGroup(this)\">Enums <span class=\"nav-badge\">%d</span></div>\n", len(a.Enums)))
		sb.WriteString("      <div class=\"nav-group-body\">\n")
		for _, en := range a.Enums {
			id := "enum-" + slug(en.Name)
			sb.WriteString(fmt.Sprintf("        <a class=\"nav-type\" href=\"#%s\" data-target=\"%s\" data-search=\"%s\" onclick=\"navigateTo('%s');return false;\">%s</a>\n",
				id, id, strings.ToLower(en.Name), id, esc(en.Name)))
		}
		sb.WriteString("      </div>\n    </div>\n")
	}

	sb.WriteString("  </div>\n</nav>\n")

	// ── Main area ─────────────────────────────────────────────────────────────
	sb.WriteString("<div class=\"main\">\n")

	// Topbar
	sb.WriteString("  <div class=\"topbar\">\n")
	sb.WriteString("    <nav class=\"breadcrumbs\" id=\"breadcrumbs\"><span class=\"bc-item\">API Reference</span></nav>\n")
	sb.WriteString("    <div class=\"topbar-right\">\n")
	sb.WriteString("      <button class=\"theme-btn\" onclick=\"toggleTheme()\" title=\"Toggle dark mode\">\U0001f319</button>\n")
	sb.WriteString("    </div>\n")
	sb.WriteString("  </div>\n")

	// Content
	sb.WriteString("  <div class=\"content\">\n")

	// Stats row
	totalActions := 0
	for _, mod := range a.Modules {
		totalActions += len(mod.Actions)
	}
	sb.WriteString("    <div class=\"stats-row\">\n")
	if multiService {
		sb.WriteString(fmt.Sprintf("      <div class=\"stat-card\"><div class=\"stat-num\">%d</div><div class=\"stat-lbl\">Services</div></div>\n", len(services)))
	}
	sb.WriteString(fmt.Sprintf("      <div class=\"stat-card\"><div class=\"stat-num\">%d</div><div class=\"stat-lbl\">Modules</div></div>\n", len(a.Modules)))
	sb.WriteString(fmt.Sprintf("      <div class=\"stat-card\"><div class=\"stat-num\">%d</div><div class=\"stat-lbl\">Endpoints</div></div>\n", totalActions))
	sb.WriteString(fmt.Sprintf("      <div class=\"stat-card\"><div class=\"stat-num\">%d</div><div class=\"stat-lbl\">Models</div></div>\n", len(a.Models)))
	if len(a.Enums) > 0 {
		sb.WriteString(fmt.Sprintf("      <div class=\"stat-card\"><div class=\"stat-num\">%d</div><div class=\"stat-lbl\">Enums</div></div>\n", len(a.Enums)))
	}
	sb.WriteString("    </div>\n\n")

	// Services → Modules → Endpoints
	for _, svc := range services {
		svcSlug := slug(svc.Name)

		if multiService {
			sb.WriteString(fmt.Sprintf("    <div class=\"svc-block\" id=\"service-%s\" data-bc=\"%s\">\n", svcSlug, esc(svc.Name)))
			sb.WriteString(fmt.Sprintf("      <h2 class=\"svc-title\">%s", esc(svc.Name)))
			if svc.BaseUrl != "" {
				sb.WriteString(fmt.Sprintf(" <code class=\"svc-url\">%s</code>", esc(svc.BaseUrl)))
			}
			sb.WriteString("</h2>\n")
			if svc.Description != "" {
				sb.WriteString(fmt.Sprintf("      <p class=\"svc-desc\">%s</p>\n", esc(svc.Description)))
			}
			sb.WriteString("    </div>\n")
		}

		for _, mn := range svc.ModuleNames {
			mod, ok := moduleByName[mn]
			if !ok {
				continue
			}
			modSlug := slug(mn)
			modBC := esc(mod.Name)
			if multiService {
				modBC = esc(svc.Name) + " \u203a " + esc(mod.Name)
			}

			sb.WriteString(fmt.Sprintf("    <div class=\"mod-header\" id=\"mod-%s-%s\" data-bc=\"%s\">\n", svcSlug, modSlug, modBC))
			sb.WriteString(fmt.Sprintf("      <h3 class=\"mod-title\">%s", esc(mod.Name)))
			if mod.Prefix != "" {
				sb.WriteString(fmt.Sprintf(" <code class=\"mod-prefix\">%s</code>", esc(mod.Prefix)))
			}
			sb.WriteString("</h3>\n")
			if mod.Description != "" {
				sb.WriteString(fmt.Sprintf("      <p class=\"mod-desc\">%s</p>\n", esc(mod.Description)))
			}
			sb.WriteString("    </div>\n")

			for _, act := range mod.Actions {
				actID := fmt.Sprintf("action-%s-%s-%s", svcSlug, modSlug, slug(act.Name))
				routePath := act.Path
				if mod.Prefix != "" {
					routePath = mod.Prefix + act.Path
				}
				method := strings.ToUpper(act.Method)
				actBC := modBC + " \u203a " + esc(act.Name)

				depCls := ""
				if act.Deprecated != "" {
					depCls = " ep-deprecated"
				}

				sb.WriteString(fmt.Sprintf("    <div class=\"ep ep-%s%s\" id=\"%s\" data-bc=\"%s\">\n", method, depCls, actID, actBC))
				sb.WriteString("      <div class=\"ep-head\" onclick=\"toggleEp(this)\">\n")
				sb.WriteString(fmt.Sprintf("        <span class=\"mtag mtag-%s\">%s</span>\n", method, method))
				sb.WriteString(fmt.Sprintf("        <span class=\"ep-path\">%s</span>\n", buildPathHTML(routePath)))
				sb.WriteString("        <span class=\"ep-info\">\n")
				sb.WriteString(fmt.Sprintf("          <span class=\"ep-name\">%s", esc(act.Name)))
				if act.Deprecated != "" {
					sb.WriteString(fmt.Sprintf(` <span class="depr-tag" title="%s">deprecated</span>`, esc(act.Deprecated)))
				}
				sb.WriteString("</span>\n")
				sb.WriteString(fmt.Sprintf("          <button class=\"copy-btn\" data-path=\"%s\" onclick=\"copyPath(event,this.dataset.path)\" title=\"Copy path\">\u2398</button>\n", esc(routePath)))
				sb.WriteString("        </span>\n")
				sb.WriteString("        <span class=\"chevron\">\u25b6</span>\n")
				sb.WriteString("      </div>\n")

				sb.WriteString("      <div class=\"ep-detail\">\n")
				if act.Description != "" {
					sb.WriteString(fmt.Sprintf("        <p class=\"ep-desc\">%s</p>\n", esc(act.Description)))
				}
				sb.WriteString("        <dl class=\"ep-meta\">\n")

				if act.Input != "" {
					sb.WriteString(fmt.Sprintf("          <dt>Input</dt><dd>%s</dd>\n", typeChip(act.Input)))
				}

				output := act.Output
				if act.OutputArray {
					output += "[]"
				}
				if output != "" {
					sb.WriteString(fmt.Sprintf("          <dt>Output</dt><dd>%s</dd>\n", typeChip(output)))
				} else {
					sb.WriteString("          <dt>Output</dt><dd><span class=\"plain-chip\">void</span></dd>\n")
				}

				if len(act.OutputFields) > 0 {
					sb.WriteString("          <dt>Response</dt><dd>\n")
					sb.WriteString("            <div class=\"field-table-wrap\"><table class=\"field-table\"><thead><tr><th>Field</th><th>Type</th><th>Attrs</th></tr></thead><tbody>\n")
					for _, f := range act.OutputFields {
						sb.WriteString(fmt.Sprintf("              <tr><td class=\"fn\">%s</td><td>%s</td><td><div class=\"attr-wrap\">%s</div></td></tr>\n",
							esc(f.Name), fieldTypeChip(f), fieldAttrs(f)))
					}
					sb.WriteString("            </tbody></table></div></dd>\n")
				}

				if act.Query != "" {
					sb.WriteString(fmt.Sprintf("          <dt>Query</dt><dd>%s</dd>\n", typeChip(act.Query)))
				}

				if len(act.QueryFields) > 0 {
					sb.WriteString("          <dt>Params</dt><dd>\n")
					sb.WriteString("            <div class=\"field-table-wrap\"><table class=\"field-table\"><thead><tr><th>Field</th><th>Type</th><th>Attrs</th></tr></thead><tbody>\n")
					for _, f := range act.QueryFields {
						sb.WriteString(fmt.Sprintf("              <tr><td class=\"fn\">%s</td><td>%s</td><td><div class=\"attr-wrap\">%s</div></td></tr>\n",
							esc(f.Name), fieldTypeChip(f), fieldAttrs(f)))
					}
					sb.WriteString("            </tbody></table></div></dd>\n")
				}

				if act.Method == "WS" {
					if act.Stream != "" {
						sb.WriteString(fmt.Sprintf("          <dt>Receive</dt><dd>%s</dd>\n", typeChip(act.Stream)))
					}
					if act.Emit != "" {
						sb.WriteString(fmt.Sprintf("          <dt>Emit</dt><dd>%s</dd>\n", typeChip(act.Emit)))
					}
				}

				if len(act.Middleware) > 0 {
					sb.WriteString("          <dt>Auth</dt><dd>")
					for i, mw := range act.Middleware {
						if i > 0 {
							sb.WriteString(" ")
						}
						sb.WriteString(fmt.Sprintf(`<span class="mw-chip">%s</span>`, esc(mw)))
					}
					sb.WriteString("</dd>\n")
				}

				if len(act.Errors) > 0 {
					sb.WriteString("          <dt>Errors</dt><dd>")
					for i, e := range act.Errors {
						if i > 0 {
							sb.WriteString(" ")
						}
						if status, ok := act.ErrorStatuses[e]; ok {
							sb.WriteString(fmt.Sprintf(`<span class="err-chip">%s <em>%d</em></span>`, esc(e), status))
						} else {
							sb.WriteString(fmt.Sprintf(`<span class="err-chip">%s</span>`, esc(e)))
						}
					}
					sb.WriteString("</dd>\n")
				}

				sb.WriteString("        </dl>\n      </div>\n    </div>\n")
			}
		}
	}

	// ── Models ────────────────────────────────────────────────────────────────
	if len(a.Models) > 0 {
		sb.WriteString("    <h2 class=\"types-title\" id=\"section-models\" data-bc=\"Models\">Models</h2>\n")
		for _, m := range a.Models {
			modelID := "model-" + slug(m.Name)
			sb.WriteString(fmt.Sprintf("    <div class=\"type-card\" id=\"%s\" data-bc=\"Models \u203a %s\">\n", modelID, esc(m.Name)))
			sb.WriteString("      <div class=\"type-head\">\n")
			sb.WriteString(fmt.Sprintf("        <span class=\"type-name\">%s</span>\n", esc(m.Name)))
			if m.Extends != "" {
				sb.WriteString(fmt.Sprintf("        <span class=\"extends-note\">extends %s</span>\n", typeChip(m.Extends)))
			}
			if m.Description != "" {
				sb.WriteString(fmt.Sprintf("        <span class=\"type-desc\">%s</span>\n", esc(m.Description)))
			}
			usedBy := collectModelUsages(a, m.Name)
			if len(usedBy) > 0 {
				sb.WriteString("        <span class=\"used-by\">Used by: ")
				for i, u := range usedBy {
					if i > 0 {
						sb.WriteString(", ")
					}
					sb.WriteString(fmt.Sprintf(`<span class="ub-chip">%s</span>`, esc(u)))
				}
				sb.WriteString("</span>\n")
			}
			sb.WriteString("      </div>\n")
			if len(m.Fields) > 0 {
				sb.WriteString("      <table class=\"fields-table\"><thead><tr><th>Field</th><th>Type</th><th>Attributes</th></tr></thead><tbody>\n")
				for _, f := range m.Fields {
					depCls := ""
					if f.Deprecated != "" {
						depCls = " class=\"depr-row\""
					}
					sb.WriteString(fmt.Sprintf("        <tr%s><td class=\"fn\">%s</td><td>%s</td><td><div class=\"attr-wrap\">%s</div></td></tr>\n",
						depCls, esc(f.Name), fieldTypeChip(f), fieldAttrs(f)))
				}
				sb.WriteString("      </tbody></table>\n")
			}
			sb.WriteString("    </div>\n")
		}
	}

	// ── Enums ─────────────────────────────────────────────────────────────────
	if len(a.Enums) > 0 {
		sb.WriteString("    <h2 class=\"types-title\" id=\"section-enums\" data-bc=\"Enums\">Enums</h2>\n")
		for _, en := range a.Enums {
			enumID := "enum-" + slug(en.Name)
			sb.WriteString(fmt.Sprintf("    <div class=\"type-card\" id=\"%s\" data-bc=\"Enums \u203a %s\">\n", enumID, esc(en.Name)))
			sb.WriteString("      <div class=\"type-head\">\n")
			sb.WriteString(fmt.Sprintf("        <span class=\"type-name\">%s</span>\n", esc(en.Name)))
			if en.Description != "" {
				sb.WriteString(fmt.Sprintf("        <span class=\"type-desc\">%s</span>\n", esc(en.Description)))
			}
			usedBy := collectEnumUsages(a, en.Name)
			if len(usedBy) > 0 {
				sb.WriteString("        <span class=\"used-by\">Used by: ")
				for i, u := range usedBy {
					if i > 0 {
						sb.WriteString(", ")
					}
					sb.WriteString(fmt.Sprintf(`<span class="ub-chip">%s</span>`, esc(u)))
				}
				sb.WriteString("</span>\n")
			}
			sb.WriteString("      </div>\n")
			sb.WriteString("      <div class=\"enum-chips\">\n")
			for _, v := range en.Values {
				sb.WriteString(fmt.Sprintf("        <span class=\"ev-chip\">%s</span>\n", esc(v)))
			}
			sb.WriteString("      </div>\n    </div>\n")
		}
	}

	sb.WriteString("    <div class=\"footer\">Generated by <strong>Veld</strong></div>\n")
	sb.WriteString("  </div>\n</div>\n")
	sb.WriteString(htmlScript)
	sb.WriteString("</body>\n</html>\n")
	return sb.String()
}

// buildPathHTML renders a route path with :param segments highlighted.
func buildPathHTML(path string) string {
	segs := strings.Split(path, "/")
	for i, seg := range segs {
		if strings.HasPrefix(seg, ":") {
			segs[i] = `<span class="path-param">` + esc(seg) + `</span>`
		} else {
			segs[i] = esc(seg)
		}
	}
	return strings.Join(segs, "/")
}

// ── Helpers ───────────────────────────────────────────────────────────────────

func slug(s string) string {
	return strings.ToLower(strings.ReplaceAll(strings.ReplaceAll(s, " ", "-"), "_", "-"))
}

func esc(s string) string {
	r := strings.NewReplacer("&", "&amp;", "<", "&lt;", ">", "&gt;", `"`, "&quot;")
	return r.Replace(s)
}

func fieldAttrs(f ast.Field) string {
	var parts []string
	if f.Optional {
		parts = append(parts, `<span class="fa-opt">optional</span>`)
	}
	if f.Default != "" {
		parts = append(parts, fmt.Sprintf(`<span class="fa-default">= %s</span>`, esc(f.Default)))
	}
	if f.Unique {
		parts = append(parts, `<span class="fa-badge">unique</span>`)
	}
	if f.Index {
		parts = append(parts, `<span class="fa-badge">index</span>`)
	}
	if f.Relation != "" {
		parts = append(parts, fmt.Sprintf(`<span class="fa-badge">&rarr; %s</span>`, esc(f.Relation)))
	}
	if f.ServerSet {
		parts = append(parts, `<span class="fa-badge">serverSet</span>`)
	}
	if f.Deprecated != "" {
		parts = append(parts, fmt.Sprintf(`<span class="fa-depr" title="%s">deprecated</span>`, esc(f.Deprecated)))
	}
	if len(parts) == 0 {
		return `<span class="fa-none">&mdash;</span>`
	}
	return strings.Join(parts, " ")
}

func collectModelUsages(a ast.AST, name string) []string {
	var usages []string
	seen := make(map[string]bool)
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			label := mod.Name + "." + act.Name
			if (act.Input == name || act.Output == name || act.Query == name) && !seen[label] {
				usages = append(usages, label)
				seen[label] = true
			}
		}
	}
	return usages
}

func collectEnumUsages(a ast.AST, name string) []string {
	var usages []string
	seen := make(map[string]bool)
	for _, m := range a.Models {
		for _, f := range m.Fields {
			if (f.Type == name || f.MapValueType == name) && !seen[m.Name] {
				usages = append(usages, m.Name)
				seen[m.Name] = true
			}
		}
	}
	return usages
}

