  --code-bg:    #f1f5f9;
  --code-fg:    #0f172a;
  --divider:    #e2e8f0;

  --accent:     #6366f1;
  --accent-dim: #4f46e5;
  --accent-bg:  #eef2ff;
  --accent-fg:  #4338ca;

  --sb-bg:       #0f172a;
  --sb-bd:       rgba(255,255,255,.06);
  --sb-fg:       #94a3b8;
  --sb-fg2:      #64748b;
  --sb-hover:    rgba(255,255,255,.05);
  --sb-act-bg:   rgba(99,102,241,.15);
  --sb-act-fg:   #a5b4fc;
  --sb-act-bd:   #6366f1;

  --get:    #10b981; --get-bg:    #d1fae5; --get-fg:    #064e3b;
  --post:   #3b82f6; --post-bg:   #dbeafe; --post-fg:   #1e3a8a;
  --put:    #f59e0b; --put-bg:    #fef3c7; --put-fg:    #78350f;
  --del:    #ef4444; --del-bg:    #fee2e2; --del-fg:    #7f1d1d;
  --patch:  #f97316; --patch-bg:  #ffedd5; --patch-fg:  #7c2d12;
  --ws:     #8b5cf6; --ws-bg:     #ede9fe; --ws-fg:     #3b0764;

  --mono: 'JetBrains Mono','Fira Code','SF Mono',Consolas,'Liberation Mono',monospace;
  --sans: -apple-system,BlinkMacSystemFont,'Inter','Segoe UI',system-ui,sans-serif;
  --r3: 3px; --r5: 5px; --r8: 8px;
}

[data-theme="dark"] {
  --bg:         #0c1222;
  --fg:         #e2e8f0;
  --sub-fg:     #cbd5e1;
  --muted:      #64748b;
  --muted2:     #475569;

  --card:       #0f172a;
  --card-bd:    #1e293b;
  --card-sh:    0 1px 4px rgba(0,0,0,.3);

  --code-bg:    #1e293b;
  --code-fg:    #e2e8f0;
  --divider:    #1e293b;

  --accent:     #818cf8;
  --accent-dim: #a5b4fc;
  --accent-bg:  rgba(99,102,241,.12);
  --accent-fg:  #c7d2fe;

  --sb-bg:       #060d19;
  --sb-bd:       rgba(255,255,255,.04);
  --sb-fg:       #64748b;
  --sb-fg2:      #475569;
  --sb-hover:    rgba(255,255,255,.04);

  --get:    #34d399; --get-bg:   rgba(5,150,105,.2);  --get-fg:   #a7f3d0;
  --post:   #60a5fa; --post-bg:  rgba(37,99,235,.2);  --post-fg:  #bfdbfe;
  --put:    #fbbf24; --put-bg:   rgba(217,119,6,.2);  --put-fg:   #fde68a;
  --del:    #f87171; --del-bg:   rgba(220,38,38,.2);  --del-fg:   #fecaca;
  --patch:  #fb923c; --patch-bg: rgba(234,88,12,.2);  --patch-fg: #fed7aa;
  --ws:     #a78bfa; --ws-bg:    rgba(124,58,237,.2); --ws-fg:    #ddd6fe;
}

/* ── Base ── */
html { scroll-behavior: smooth; }
body {
  font-family: var(--sans);
  background: var(--bg);
  color: var(--fg);
  line-height: 1.6;
  display: grid;
  grid-template-columns: 260px 1fr;
  min-height: 100vh;
}
a { color: inherit; text-decoration: none; }

/* ── Sidebar ── */
.sidebar {
  background: var(--sb-bg);
  height: 100vh;
  position: sticky;
  top: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border-right: 1px solid var(--sb-bd);
}

.sidebar-brand {
  padding: 18px 16px 14px;
  border-bottom: 1px solid var(--sb-bd);
  flex-shrink: 0;
}
.brand-name {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  font-weight: 700;
  color: #f1f5f9;
  letter-spacing: -.01em;
}
.brand-icon { width: 18px; height: 18px; color: var(--accent); flex-shrink: 0; }
.brand-sub  { font-size: 11px; color: var(--sb-fg2); margin-top: 3px; }

/* Search */
.search-wrap {
  padding: 10px 12px;
  border-bottom: 1px solid var(--sb-bd);
  flex-shrink: 0;
}
.search-inner { position: relative; display: flex; align-items: center; }
.search-icon-svg {
  position: absolute;
  left: 9px;
  color: var(--sb-fg2);
  pointer-events: none;
  flex-shrink: 0;
}
#nav-search {
  width: 100%;
  background: rgba(255,255,255,.06);
  border: 1px solid rgba(255,255,255,.1);
  border-radius: var(--r5);
  padding: 6px 30px 6px 28px;
  font-size: 12px;
  color: #f1f5f9;
  outline: none;
  font-family: var(--sans);
  transition: border-color .15s, background .15s;
}
#nav-search::placeholder { color: var(--sb-fg2); }
#nav-search:focus { border-color: var(--accent); background: rgba(255,255,255,.09); }
.search-hint {
  position: absolute;
  right: 8px;
  font-size: 10px;
  color: var(--sb-fg2);
  background: rgba(255,255,255,.07);
  padding: 1px 5px;
  border-radius: 3px;
  border: 1px solid rgba(255,255,255,.1);
  font-family: var(--sans);
  pointer-events: none;
  transition: opacity .15s;
}
#nav-search:focus ~ .search-hint,
#nav-search:not(:placeholder-shown) ~ .search-hint { opacity: 0; }

/* Nav tree */
.nav-tree {
  flex: 1;
  overflow-y: auto;
  padding: 6px 0 24px;
  scrollbar-width: thin;
  scrollbar-color: rgba(255,255,255,.08) transparent;
}
.nav-tree::-webkit-scrollbar { width: 3px; }
.nav-tree::-webkit-scrollbar-thumb { background: rgba(255,255,255,.08); border-radius: 2px; }

/* Service block */
.nav-svc { margin-bottom: 4px; }
.nav-svc-label {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 16px 4px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: .08em;
  text-transform: uppercase;
  color: var(--sb-fg);
  cursor: pointer;
  user-select: none;
  transition: color .15s;
}
.nav-svc-label:hover { color: #cbd5e1; }
.nav-toggle { font-size: 9px; transition: transform .2s; display: inline-block; }
.nav-svc.collapsed .nav-toggle  { transform: rotate(-90deg); }
.nav-svc.collapsed .nav-svc-body { display: none; }

/* Module block */
.nav-mod { margin-bottom: 1px; }
.nav-mod-label {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 5px 16px;
  font-size: 11px;
  font-weight: 600;
  color: var(--sb-fg);
  cursor: pointer;
  user-select: none;
  transition: color .12s, background .12s;
}
.nav-mod-label:hover { color: #cbd5e1; background: var(--sb-hover); }
.nav-badge {
  font-size: 9px;
  font-weight: 700;
  background: rgba(255,255,255,.08);
  color: var(--sb-fg2);
  padding: 1px 6px;
  border-radius: 10px;
  flex-shrink: 0;
}
.nav-mod.collapsed .nav-mod-body { display: none; }

/* Endpoint nav link */
.nav-ep {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 3px 12px 3px 20px;
  font-size: 11.5px;
  color: var(--sb-fg);
  cursor: pointer;
  transition: color .12s, background .12s;
  border-left: 2px solid transparent;
  overflow: hidden;
  text-decoration: none;
}
.nav-ep:hover { color: #e2e8f0; background: var(--sb-hover); }
.nav-ep.active {
  color: var(--sb-act-fg);
  background: var(--sb-act-bg);
  border-left-color: var(--sb-act-bd);
}
.nav-method {
  font-size: 9px;
  font-weight: 800;
