.nav-method-POST   { color: var(--post); }
.nav-method-PUT    { color: var(--put); }
.nav-method-DELETE { color: var(--del); }
.nav-method-PATCH  { color: var(--patch); }
.nav-method-WS     { color: var(--ws); }
.nav-ep-name { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }

/* Type groups (models / enums) */
.nav-group { margin-top: 10px; }
.nav-group-label {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 16px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: .08em;
  text-transform: uppercase;
  color: var(--sb-fg2);
  cursor: pointer;
  user-select: none;
  transition: color .15s;
}
.nav-group-label:hover { color: var(--sb-fg); }
.nav-group.collapsed .nav-group-body { display: none; }
.nav-type {
  display: block;
  padding: 3px 16px 3px 20px;
  font-size: 11.5px;
  font-family: var(--mono);
  color: var(--sb-fg2);
