/* ── Main layout ── */
.main { display: flex; flex-direction: column; min-height: 100vh; }

/* Topbar */
.topbar {
  position: sticky;
  top: 0;
  z-index: 10;
  background: var(--bg);
  border-bottom: 1px solid var(--divider);
  padding: 0 40px;
  height: 44px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
}
.breadcrumbs {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 12px;
  min-width: 0;
  overflow: hidden;
}
.bc-item { color: var(--muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.bc-item.bc-last { color: var(--fg); font-weight: 500; }
.bc-sep { color: var(--muted2); flex-shrink: 0; }
.topbar-right { display: flex; align-items: center; flex-shrink: 0; }
.theme-btn {
  width: 30px; height: 30px;
  background: var(--card);
  border: 1px solid var(--card-bd);
  border-radius: var(--r5);
  cursor: pointer;
  font-size: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: border-color .15s;
  line-height: 1;
}
.theme-btn:hover { border-color: var(--accent); }

/* Content */
.content { flex: 1; padding: 32px 40px 64px; max-width: 900px; }

/* Stats */
.stats-row { display: flex; gap: 12px; margin-bottom: 36px; flex-wrap: wrap; }
.stat-card {
  background: var(--card);
  border: 1px solid var(--card-bd);
  border-radius: var(--r8);
  padding: 14px 20px;
  box-shadow: var(--card-sh);
  min-width: 100px;
  text-align: center;
}
.stat-num {
  font-size: 26px;
  font-weight: 800;
  color: var(--accent);
  line-height: 1;
  letter-spacing: -.02em;
}
.stat-lbl {
  font-size: 10px;
  color: var(--muted);
  margin-top: 5px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: .05em;
}

/* Service + Module headers */
.svc-block  { margin: 32px 0 8px; }
.svc-title {
  font-size: 22px;
  font-weight: 800;
  letter-spacing: -.025em;
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}
.svc-url {
  font-size: 11px;
  font-weight: 400;
  color: var(--muted);
  background: var(--code-bg);
  padding: 2px 8px;
  border-radius: var(--r3);
  font-family: var(--mono);
}
