// generateModuleRoutes writes internal/routes/{module}.go with:
//   - setup{Module}Routes registration function
//   - One handler closure per action
func (e *GoEmitter) generateModuleRoutes(a ast.AST, mod ast.Module, outDir string, strat gostrategy.GoFrameworkStrategy) error {
	w := codegen.NewWriter("\t")
	w.Writeln(header)
	w.Writeln("package routes")
	w.BlankLine()

	// Determine which imports are needed.
	hasInput := moduleHasInput(mod)

	im := codegen.NewImportManager()
	for _, imp := range strat.GoImports() {
		if imp == "net/http" {
			im.Add(imp, codegen.GroupStdlib)
		} else {
			im.Add(imp, codegen.GroupThirdParty)
		}
	}
	im.Add(goModuleName+"/internal/interfaces", codegen.GroupLocal)
	if hasInput {
		im.Add(goModuleName+"/internal/models", codegen.GroupLocal)
	}

	w.Write(im.Format("go"))
	w.BlankLine()

	// setup{Module}Routes — registers each action's handler.
	setupFuncName := e.adapter.NamingConvention("setup"+mod.Name+"Routes", lang.NamingContextPrivate)
	svcType := "interfaces." + e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
	svcArg := e.adapter.NamingConvention(mod.Name+"Svc", lang.NamingContextPrivate)
	routerParamType := strat.RouterParamType()

	w.Writeln(fmt.Sprintf("// %s registers the %s module routes.", setupFuncName, mod.Name))
	w.WriteBlock(fmt.Sprintf("func %s(r %s, %s %s) {", setupFuncName, routerParamType, svcArg, svcType))

	for _, act := range mod.Actions {
		routePath := fullPath(mod, act)
		if act.Method == "WS" {
			actionName := e.adapter.NamingConvention(act.Name, lang.NamingContextExported)
			pathParams := emitter.ExtractPathParams(routePath)
			wsCode := strat.WSHandlerCode(actionName, routePath, act.Stream, act.Emit, pathParams, svcArg, svcType)
			for _, line := range strings.Split(strings.TrimRight(wsCode, "\n"), "\n") {
				// Strip leading tab since WriteBlock already indented once.
				w.Writeln(strings.TrimPrefix(line, "\t"))
			}
		} else {
			chiPath := emitter.ToChiPath(routePath)
			handlerName := e.adapter.NamingConvention(act.Name+"Handler", lang.NamingContextPrivate)
			w.Writeln(strat.RegisterRoute(act.Method, chiPath, handlerName+"("+svcArg+")"))
		}
	}

	w.Dedent()
	w.Writeln("}")

	// Handler function per action (skip WS actions — they are inline stubs).
	for _, act := range mod.Actions {
		if act.Method == "WS" {
			continue
		}
		w.BlankLine()
		if err := e.writeHandler(w, mod, act, svcType, strat); err != nil {
			return err
		}
	}

	dir := filepath.Join(outDir, "internal", "routes")
	fileName := strings.ToLower(mod.Name) + ".go"
	return os.WriteFile(filepath.Join(dir, fileName), w.Bytes(), 0644)
}

// writeHandler generates a single http.HandlerFunc closure for an action.
func (e *GoEmitter) writeHandler(w *codegen.Writer, mod ast.Module, act ast.Action, svcType string, strat gostrategy.GoFrameworkStrategy) error {
	handlerName := e.adapter.NamingConvention(act.Name+"Handler", lang.NamingContextPrivate)
	methodName := e.adapter.NamingConvention(act.Name, lang.NamingContextExported)
	routePath := fullPath(mod, act)
	pathParams := emitter.ExtractPathParams(routePath)

	hasInput := act.Input != ""
	hasOutput := act.Output != ""

	if act.Description != "" {
		w.Writeln(fmt.Sprintf("// %s — %s", handlerName, act.Description))
	} else {
		w.Writeln(fmt.Sprintf("// %s handles %s %s requests.", handlerName, strings.ToUpper(act.Method), routePath))
	}

	// Outer function: returns the handler closure bound to the service.
	w.WriteBlock(fmt.Sprintf("func %s(svc %s) http.HandlerFunc {", handlerName, svcType))
	w.WriteBlock("return func(w http.ResponseWriter, r *http.Request) {")

	// 1. Extract path parameters using the strategy (Chi vs plain net/http differ here).
	for _, p := range pathParams {
		varName := e.adapter.NamingConvention(p, lang.NamingContextPrivate)
		w.Writeln(strat.ExtractPathParam(varName, p))
	}
	if len(pathParams) > 0 {
		w.BlankLine()
	}

	// 2. Decode request body (if the action has input).
	if hasInput {
		w.Writeln(fmt.Sprintf("var req models.%s", act.Input))
		w.WriteBlock("if err := readJSON(r, &req); err != nil {")
		w.Writeln("writeJSON(w, http.StatusBadRequest, map[string]interface{}{\"error\": \"invalid request body\"})")
		w.Writeln("return")
		w.Dedent()
		w.Writeln("}")
		w.BlankLine()
	}

	// 3. Build service call arguments.
	callArgs := buildCallArgs(e, act, pathParams)

	// 4. Invoke service and handle error.
	if hasOutput {
		w.Writeln(fmt.Sprintf("resp, err := svc.%s(%s)", methodName, strings.Join(callArgs, ", ")))
	} else {
		w.Writeln(fmt.Sprintf("err := svc.%s(%s)", methodName, strings.Join(callArgs, ", ")))
	}

	w.WriteBlock("if err != nil {")
	w.Writeln("writeJSON(w, http.StatusInternalServerError, map[string]interface{}{\"error\": err.Error()})")
	w.Writeln("return")
	w.Dedent()
	w.Writeln("}")
	w.BlankLine()

	// 5. Write success response.
	statusCode := emitter.SuccessStatusForAction(act)
	if hasOutput {
		w.Writeln(fmt.Sprintf("writeJSON(w, %s, resp)", goHTTPStatus(statusCode)))
	} else if statusCode == 204 {
		w.Writeln("w.WriteHeader(http.StatusNoContent)")
	} else {
		w.Writeln(fmt.Sprintf("writeJSON(w, %s, nil)", goHTTPStatus(statusCode)))
	}

	// Close inner function (return func body).
	w.Dedent()
	w.Writeln("}")
	// Close outer function.
	w.Dedent()
	w.Writeln("}")
	return nil
}

// ── small helpers ─────────────────────────────────────────────────────────────

// fullPath joins the module prefix and action path.
func fullPath(mod ast.Module, act ast.Action) string {
	if mod.Prefix != "" {
		return mod.Prefix + act.Path
	}
	return act.Path
}

// goHTTPStatus maps an integer status code to a Go http.StatusXxx constant string.
func goHTTPStatus(code int) string {
	switch code {
	case 200:
		return "http.StatusOK"
	case 201:
		return "http.StatusCreated"
	case 202:
		return "http.StatusAccepted"
	case 204:
		return "http.StatusNoContent"
	default:
		return fmt.Sprintf("%d", code)
	}
}

// buildCallArgs constructs the argument list for the service method call.
func buildCallArgs(e *GoEmitter, act ast.Action, pathParams []string) []string {
	var args []string
	args = append(args, "r.Context()")

	for _, p := range pathParams {
		args = append(args, e.adapter.NamingConvention(p, lang.NamingContextPrivate))
	}
	if act.Input != "" {
		args = append(args, "&req")
	}
	if act.Query != "" {
		// Query params are not automatically decoded; pass nil so the interface compiles.
		// Users should decode query params from r.URL.Query() in their service or wrap the handler.
		args = append(args, "nil")
	}
	if act.Headers != "" {
		// Headers are not automatically decoded; pass nil so the interface compiles.
		// Users should extract headers from r.Header in their service or wrap the handler.
		args = append(args, "nil")
	}
	return args
}

// moduleHasPathParams returns true if any action in the module has path parameters.
func moduleHasPathParams(mod ast.Module) bool {
	for _, act := range mod.Actions {
		if len(emitter.ExtractPathParams(fullPath(mod, act))) > 0 {
			return true
		}
	}
	return false
}

// moduleHasInput returns true if any action in the module has a request body.
func moduleHasInput(mod ast.Module) bool {
	for _, act := range mod.Actions {
		if act.Input != "" {
			return true
		}
	}
	return false
}

package java

// routes.go — emits controllers/{Module}Controller.java.
// All framework-specific annotations and response building are delegated
// to the FrameworkStrategy; this file only owns Java structure.

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	jstrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/java/strategy"
)

const javaPackageControllers = "maayn.veld.generated.controllers"

func (e *JavaEmitter) emitController(strat jstrategy.FrameworkStrategy, a ast.AST, mod ast.Module, outDir string) error {
	dir := pkgToDir(outDir, javaPackageControllers)

	enumNames := make(map[string]bool, len(a.Enums))
	for _, en := range a.Enums {
		enumNames[en.Name] = true
	}

	modClass := capitalize(mod.Name)

	// Determine which extra imports the controller needs.
	needsList := false
	for _, act := range mod.Actions {
		rt := javaReturnType(act, enumNames)
		if strings.HasPrefix(rt, "List<") {
			needsList = true
			break
		}
	}

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString(fmt.Sprintf("package %s;\n\n", javaPackageControllers))
	for _, imp := range javaModuleModelImports(a, mod) {
		sb.WriteString(imp + "\n")
	}
	sb.WriteString(fmt.Sprintf("import %s.*;\n", javaPackageErrors))
	sb.WriteString(fmt.Sprintf("import %s.I%sService;\n", javaPackageServices, modClass))
	if needsList {
		sb.WriteString("import java.util.List;\n")
	}
	for _, imp := range strat.ControllerImports() {
		sb.WriteString(fmt.Sprintf("import %s;\n", imp))
	}
	sb.WriteString("\n")

	if mod.Description != "" {
		sb.WriteString(fmt.Sprintf("/** %s */\n", mod.Description))
	}
	for _, ann := range strat.ControllerAnnotations(mod) {
		sb.WriteString(ann + "\n")
	}
	sb.WriteString(fmt.Sprintf("public class %sController {\n\n", modClass))
	sb.WriteString(fmt.Sprintf("    private final I%sService service;\n\n", modClass))
	sb.WriteString(fmt.Sprintf("    public %sController(I%sService service) {\n", modClass, modClass))
	sb.WriteString("        this.service = service;\n")
	sb.WriteString("    }\n")

	for _, act := range mod.Actions {
		if act.Method == "WS" {
			routePath := act.Path
			if mod.Prefix != "" {
				routePath = mod.Prefix + act.Path
			}
			emitType := act.Emit
			if emitType == "" {
				emitType = "String"
			}
			sb.WriteString(strat.WSControllerMethod(capitalize(act.Name), routePath, emitType, act.Stream))
		} else {
			e.writeHandler(strat, &sb, act, enumNames)
		}
	}

	sb.WriteString("}\n")
	return os.WriteFile(filepath.Join(dir, modClass+"Controller.java"), []byte(sb.String()), 0644)
}

// writeHandler appends a single handler method to sb.
func (e *JavaEmitter) writeHandler(strat jstrategy.FrameworkStrategy, sb *strings.Builder, act ast.Action, enumNames map[string]bool) {
	pathParams := emitter.ExtractPathParams(act.Path)
	returnType := javaReturnType(act, enumNames)

	sb.WriteString("\n")
	if act.Description != "" {
		sb.WriteString(fmt.Sprintf("    /** %s */\n", act.Description))
	}
	sb.WriteString(fmt.Sprintf("    %s\n", strat.RouteAnnotation(act.Method, act.Path)))

	methodName := javaCamelField(act.Name)
	var params []string
	for _, p := range pathParams {
		ann := strat.PathParamAnnotation(p)
		if ann != "" {
			params = append(params, fmt.Sprintf("%s String %s", ann, javaCamelField(p)))
		} else {
			params = append(params, fmt.Sprintf("String %s", javaCamelField(p)))
		}
	}
	if act.Input != "" {
		ann := strat.InputParamAnnotation()
		if ann != "" {
			params = append(params, fmt.Sprintf("%s %s body", ann, act.Input))
		} else {
			params = append(params, fmt.Sprintf("%s body", act.Input))
		}
	}
	if act.Query != "" {
		ann := strat.QueryParamAnnotation()
		if ann != "" {
			params = append(params, fmt.Sprintf("%s %s query", ann, act.Query))
		} else {
			params = append(params, fmt.Sprintf("%s query", act.Query))
		}
	}
	if act.Headers != "" {
		params = append(params, fmt.Sprintf("%s headers", act.Headers))
	}

	sb.WriteString(fmt.Sprintf("    public %s %s(%s) {\n", strat.ResponseWrapper(), methodName, strings.Join(params, ", ")))
	sb.WriteString("        try {\n")

	var callArgs []string
	for _, p := range pathParams {
		callArgs = append(callArgs, javaCamelField(p))
	}
	if act.Input != "" {
		callArgs = append(callArgs, "body")
	}
	if act.Query != "" {
		callArgs = append(callArgs, "query")
	}
	if act.Headers != "" {
		callArgs = append(callArgs, "headers")
	}

	serviceCall := fmt.Sprintf("service.%s(%s)", methodName, strings.Join(callArgs, ", "))

	switch {
	case returnType == "void" && act.Method == "DELETE":
		sb.WriteString(fmt.Sprintf("            %s;\n", serviceCall))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.NoContentResponse()))
	case returnType == "void" && act.Method == "POST":
		// POST with no output — call service, return 201 with no body
		sb.WriteString(fmt.Sprintf("            %s;\n", serviceCall))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.CreatedResponse("null")))
	case returnType == "void":
		sb.WriteString(fmt.Sprintf("            %s;\n", serviceCall))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.OkResponse("null")))
	case act.Method == "POST":
		sb.WriteString(fmt.Sprintf("            %s result = %s;\n", returnType, serviceCall))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.CreatedResponse("result")))
	default:
		sb.WriteString(fmt.Sprintf("            %s result = %s;\n", returnType, serviceCall))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.OkResponse("result")))
	}

	sb.WriteString("        } catch (ApiException e) {\n")
	sb.WriteString(fmt.Sprintf("            %s\n", strat.ApiExceptionCatch("e")))
	sb.WriteString("        } catch (Exception e) {\n")
	sb.WriteString(fmt.Sprintf("            %s\n", strat.ErrorResponse("e")))
	sb.WriteString("        }\n")
	sb.WriteString("    }\n")
}

