package strategy

import "github.com/Adhamzineldin/Veld/internal/ast"

// FrameworkStrategy provides framework-specific code generation rules for a Java HTTP
// backend. Swap implementations to target Spring Boot, Micronaut, Quarkus, or plain Java.
type FrameworkStrategy interface {
	// ControllerAnnotations returns class-level annotations for a module controller.
	ControllerAnnotations(mod ast.Module) []string
	// RouteAnnotation returns the handler method annotation, e.g. @GetMapping("/path").
	RouteAnnotation(method, path string) string
	// InputParamAnnotation returns the annotation for a request body parameter.
	InputParamAnnotation() string
	// PathParamAnnotation returns the annotation for a named path variable.
	PathParamAnnotation(name string) string
	// QueryParamAnnotation returns the annotation for query parameters.
	QueryParamAnnotation() string
	// QueryParamType returns the fully-qualified Java type for query params.
	QueryParamType() string
	// ResponseWrapper returns the handler return type, e.g. "ResponseEntity<?>".
	ResponseWrapper() string
	// OkResponse returns a return statement for a 200 OK response wrapping expr.
	OkResponse(expr string) string
	// CreatedResponse returns a return statement for a 201 Created response wrapping expr.
	CreatedResponse(expr string) string
	// NoContentResponse returns a return statement for a 204 No Content response.
	NoContentResponse() string
	// ApiExceptionCatch returns a catch block body for ApiException — preserves the
	// typed HTTP status and machine-readable code set by the service layer.
	ApiExceptionCatch(errVar string) string
	// ErrorResponse returns a return statement for an unexpected 500 error using errVar.
	ErrorResponse(errVar string) string
	// ControllerImports returns framework imports required in controller files.
	ControllerImports() []string
	// MiddlewareImports returns framework imports required in middleware files.
	MiddlewareImports() []string
	// ValidationImports returns framework imports required in validation files.
	ValidationImports() []string
	// GlobalExceptionHandlerSource returns the complete source of GlobalExceptionHandler.java.
	// Return an empty string to skip generating the file.
	GlobalExceptionHandlerSource(ctrlPkg, modelsPkg string) string
	// BuildFile returns the build descriptor filename and its full contents.
	BuildFile() (name, content string)
	// WSControllerMethod returns the Java controller method stub(s) for a WebSocket action.
	// actionName: PascalCase action name, routePath: full route path,
	// emitType: client→server Java type (may be "String"), streamType: server→client type (may be "").
	WSControllerMethod(actionName, routePath, emitType, streamType string) string
	// InterceptorSource returns the complete source for {Label}Interceptor.java.
	// label is the PascalCase middleware label (e.g. "AuthGuard").
	// Returns "" if the framework does not use interceptors.
	InterceptorSource(label, middlewarePkg string) string
	// WebMvcConfigurerSource returns VeldWebMvcConfigurer.java that registers every
	// interceptor against the exact path patterns derived from the AST.
	// pathMap: label → slice of full paths (prefix + action path), already de-duped.
	// Returns "" if the framework does not use interceptors.
	WebMvcConfigurerSource(pathMap map[string][]string, controllerPkg, middlewarePkg string) string
	// AutoConfigSource returns VeldAutoConfiguration.java so generated controllers and
	// interceptors are registered without the user touching their @SpringBootApplication.
	// Returns "" if not needed for this framework.
	AutoConfigSource(basePkg string) string
}

// New returns the FrameworkStrategy for the given name.
// Empty string or "plain" → PlainStrategy (no framework dependency).
// "spring" or "spring-boot" → SpringStrategy (Spring Boot 3.x / 4.x).
func New(framework string) FrameworkStrategy {
	switch framework {
	case "spring", "spring-boot":
		return &SpringStrategy{}
	default: // "", "plain"
		return &PlainStrategy{}
	}
}

package strategy

import "github.com/Adhamzineldin/Veld/internal/ast"

// FrameworkStrategy provides framework-specific code generation rules for a Java HTTP
// backend. Swap implementations to target Spring Boot, Micronaut, Quarkus, or plain Java.
type FrameworkStrategy interface {
	// ControllerAnnotations returns class-level annotations for a module controller.
	ControllerAnnotations(mod ast.Module) []string
	// RouteAnnotation returns the handler method annotation, e.g. @GetMapping("/path").
	RouteAnnotation(method, path string) string
	// InputParamAnnotation returns the annotation for a request body parameter.
	InputParamAnnotation() string
	// PathParamAnnotation returns the annotation for a named path variable.
	PathParamAnnotation(name string) string
	// QueryParamAnnotation returns the annotation for query parameters.
	QueryParamAnnotation() string
	// QueryParamType returns the fully-qualified Java type for query params.
	QueryParamType() string
	// ResponseWrapper returns the handler return type, e.g. "ResponseEntity<?>".
	ResponseWrapper() string
	// OkResponse returns a return statement for a 200 OK response wrapping expr.
	OkResponse(expr string) string
	// CreatedResponse returns a return statement for a 201 Created response wrapping expr.
	CreatedResponse(expr string) string
	// NoContentResponse returns a return statement for a 204 No Content response.
	NoContentResponse() string
	// StatusResponse returns a return statement for a custom HTTP status response wrapping expr.
	StatusResponse(code int, expr string) string
	// ApiExceptionCatch returns a catch block body for ApiException — preserves the
	// typed HTTP status and machine-readable code set by the service layer.
	ApiExceptionCatch(errVar string) string
	// ErrorResponse returns a return statement for an unexpected 500 error using errVar.
	ErrorResponse(errVar string) string
	// ControllerImports returns framework imports required in controller files.
	ControllerImports() []string
	// MiddlewareImports returns framework imports required in middleware files.
	MiddlewareImports() []string
	// ValidationImports returns framework imports required in validation files.
	ValidationImports() []string
	// GlobalExceptionHandlerSource returns the complete source of GlobalExceptionHandler.java.
	// Return an empty string to skip generating the file.
	GlobalExceptionHandlerSource(ctrlPkg, modelsPkg string) string
	// BuildFile returns the build descriptor filename and its full contents.
	BuildFile() (name, content string)
	// WSControllerMethod returns the Java controller method stub(s) for a WebSocket action.
	// actionName: PascalCase action name, routePath: full route path,
	// emitType: client→server Java type (may be "String"), streamType: server→client type (may be "").
	WSControllerMethod(actionName, routePath, emitType, streamType string) string
	// InterceptorSource returns the complete source for {Label}Interceptor.java.
	// label is the PascalCase middleware label (e.g. "AuthGuard").
	// Returns "" if the framework does not use interceptors.
	InterceptorSource(label, middlewarePkg string) string
	// WebMvcConfigurerSource returns VeldWebMvcConfigurer.java that registers every
	// interceptor against the exact path patterns derived from the AST.
	// pathMap: label → slice of full paths (prefix + action path), already de-duped.
	// Returns "" if the framework does not use interceptors.
	WebMvcConfigurerSource(pathMap map[string][]string, controllerPkg, middlewarePkg string) string
	// AutoConfigSource returns VeldAutoConfiguration.java so generated controllers and
	// interceptors are registered without the user touching their @SpringBootApplication.
	// Returns "" if not needed for this framework.
	AutoConfigSource(basePkg string) string
}

// New returns the FrameworkStrategy for the given name.
// Empty string or "plain" → PlainStrategy (no framework dependency).
// "spring" or "spring-boot" → SpringStrategy (Spring Boot 3.x / 4.x).
func New(framework string) FrameworkStrategy {
	switch framework {
	case "spring", "spring-boot":
		return &SpringStrategy{}
	default: // "", "plain"
		return &PlainStrategy{}
	}
}

package javascript

// routes.go — emits routes/{module}.routes.js with try/catch and
// correct HTTP status codes (201 for POST, 204 for DELETE with no output).
// Plain JavaScript — no type annotations.

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	jsstrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/javascript/strategy"
)

func (e *JSEmitter) emitRoutes(a ast.AST, mod ast.Module, outDir string, opts emitter.EmitOptions, strat jsstrategy.JSFrameworkStrategy) error {
	dir := filepath.Join(outDir, "routes")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	moduleLower := strings.ToLower(mod.Name)
	funcName := moduleLower + "Router"
	allMiddleware := emitter.CollectModuleMiddleware(mod)

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD — DO NOT EDIT\n")

	if emitter.HasErrors(mod) {
		sb.WriteString(fmt.Sprintf("const { ApiError } = require('../errors/%s.errors');\n", moduleLower))
	}

	// When validation is enabled, import the generated zero-dep validators.
	if opts.Validate {
		if imports := buildValidatorImports(mod); len(imports) > 0 {
			sb.WriteString(fmt.Sprintf("const { %s } = require('../_validators');\n", strings.Join(imports, ", ")))
		}
	}

	sb.WriteString("\n")

	// JSDoc for the function signature.
	sb.WriteString("/**\n")
	sb.WriteString(fmt.Sprintf(" * Registers %s module routes.\n", mod.Name))
	sb.WriteString(fmt.Sprintf(" * @param {%s} router\n", strat.RouterType()))
	sb.WriteString(fmt.Sprintf(" * @param {import('../interfaces/I%sService').I%sService} service\n", mod.Name, mod.Name))
	if len(allMiddleware) > 0 {
		sb.WriteString(" * @param {Object} middleware\n")
	}
	sb.WriteString(" */\n")

	if len(allMiddleware) > 0 {
		sb.WriteString(fmt.Sprintf("function %s(router, service, middleware) {\n", funcName))
	} else {
		sb.WriteString(fmt.Sprintf("function %s(router, service) {\n", funcName))
	}

	for _, act := range mod.Actions {
		writeJSRouteHandler(&sb, mod, act, opts, strat)
	}

	sb.WriteString("}\n\n")
	sb.WriteString(fmt.Sprintf("module.exports = { %s };\n", funcName))

	if err := os.WriteFile(filepath.Join(dir, moduleLower+".routes.js"), []byte(sb.String()), 0644); err != nil {
		return err
	}

	if len(allMiddleware) > 0 {
		return e.emitMiddlewareInterface(mod, allMiddleware, outDir, strat)
	}
	return nil
}

// writeJSRouteHandler appends a single route registration + async handler to sb.
func writeJSRouteHandler(sb *strings.Builder, mod ast.Module, act ast.Action, opts emitter.EmitOptions, strat jsstrategy.JSFrameworkStrategy) {
	method := strings.ToLower(act.Method)
	routePath := act.Path
	if mod.Prefix != "" {
		routePath = mod.Prefix + act.Path
	}
	camelName := emitter.ToCamelCase(act.Name)

	if act.Description != "" {
		sb.WriteString(fmt.Sprintf("\n  // %s\n", act.Description))
	}

	// WebSocket actions: commented stub only.
	if act.Method == "WS" {
		sb.WriteString(fmt.Sprintf("\n  // WebSocket: %s\n", routePath))
		sb.WriteString("  // To handle this route, set up a WebSocket server (e.g. 'ws' package)\n")
		sb.WriteString(fmt.Sprintf("  // and call service.%s(ws", camelName))
		for _, p := range emitter.ExtractPathParams(routePath) {
			sb.WriteString(fmt.Sprintf(", %s", p))
		}
		sb.WriteString(") on connection.\n")
		return
	}

	mwArgs := ""
	for _, mw := range act.Middleware {
		mwArgs += fmt.Sprintf("middleware.%s, ", mw)
	}

	sb.WriteString(fmt.Sprintf("\n  router.%s('%s', %sasync (req, res) => {\n", method, routePath, mwArgs))
	sb.WriteString("    try {\n")

	// Build service call arguments.
	pathParams := emitter.ExtractPathParams(routePath)
	callArgs := make([]string, 0, len(pathParams)+2)
	for _, p := range pathParams {
		callArgs = append(callArgs, fmt.Sprintf("req.params.%s", p))
	}

	if act.Input != "" {
		if opts.Validate {
			sb.WriteString(fmt.Sprintf("      const body = parse%s(req.body);\n", act.Input))
			callArgs = append(callArgs, "body")
		} else {
			callArgs = append(callArgs, "req.body")
		}
	}

	if act.Query != "" {
		callArgs = append(callArgs, "req.query")
	}

	if act.Headers != "" {
		callArgs = append(callArgs, "req.headers")
	}

	serviceCall := fmt.Sprintf("service.%s(%s)", camelName, strings.Join(callArgs, ", "))

	switch {
	case act.Method == "DELETE" && act.Output == "":
		sb.WriteString(fmt.Sprintf("      await %s;\n", serviceCall))
		sb.WriteString("      res.status(204).end();\n")

	case act.Method == "POST":
		sb.WriteString(fmt.Sprintf("      const result = await %s;\n", serviceCall))
		if opts.Validate && act.Output != "" {
			writeJSOutputAssertion(sb, act)
		}
		sb.WriteString("      res.status(201).json(result);\n")

	default:
		sb.WriteString(fmt.Sprintf("      const result = await %s;\n", serviceCall))
		if opts.Validate && act.Output != "" {
			writeJSOutputAssertion(sb, act)
		}
		sb.WriteString("      res.json(result);\n")
	}

	sb.WriteString("    } catch (err) {\n")
	sb.WriteString("      const status = err.status ?? err.statusCode ?? 500;\n")
	sb.WriteString("      const body = { error: err.message ?? 'Internal Server Error' };\n")
	sb.WriteString("      if (err.code) body.code = err.code;\n")
	sb.WriteString("      res.status(status).json(body);\n")
	sb.WriteString("    }\n")
	sb.WriteString("  });\n")
}

// writeJSOutputAssertion emits assertX(result) or assertXArray(result).
func writeJSOutputAssertion(sb *strings.Builder, act ast.Action) {
	if act.OutputArray {
		sb.WriteString(fmt.Sprintf("      assert%sArray(result);\n", act.Output))
	} else {
		sb.WriteString(fmt.Sprintf("      assert%s(result);\n", act.Output))
	}
}

// emitMiddlewareInterface writes interfaces/I{Module}Middleware.js.
func (e *JSEmitter) emitMiddlewareInterface(mod ast.Module, allMiddleware []string, outDir string, strat jsstrategy.JSFrameworkStrategy) error {
	dir := filepath.Join(outDir, "middleware")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	interfaceName := "I" + mod.Name + "Middleware"
	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD — DO NOT EDIT\n\n")
	sb.WriteString("/**\n")
	sb.WriteString(fmt.Sprintf(" * Middleware interface for the %s module.\n", mod.Name))
	sb.WriteString(" * Implement this object and pass it to the route registrar.\n")
	sb.WriteString(fmt.Sprintf(" * @typedef {Object} %s\n", interfaceName))
	for _, mw := range allMiddleware {
		camelMw := emitter.ToCamelCase(mw)
		sb.WriteString(fmt.Sprintf(" * @property {function(%s, %s, function): void} %s - %s middleware handler\n", strat.RouterType(), strat.RouterType(), camelMw, mw))
	}
	sb.WriteString(" */\n\n")
	sb.WriteString(fmt.Sprintf("module.exports = {};\n"))

	return os.WriteFile(filepath.Join(dir, interfaceName+".js"), []byte(sb.String()), 0644)
}

