package python

// routes.go — emits routes/{module}_routes.py with try/except and
// correct HTTP status codes (201 for POST, 204 for DELETE with no output).
//
// When EmitOptions.Validate is true, route handlers are augmented with:
//   - parse_x(body)   — validates input shape before passing to service (→ 400)
//   - assert_x(result) — guards output shape before sending to client   (→ 500)

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	pystrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/python/strategy"
)

func (e *PythonEmitter) emitRoutes(mod ast.Module, outDir string, opts emitter.EmitOptions, strat pystrategy.PythonFrameworkStrategy) error {
	dir := filepath.Join(outDir, "routes")
	moduleLower := strings.ToLower(mod.Name)

	allMiddleware := emitter.CollectModuleMiddleware(mod)
	hasMiddleware := len(allMiddleware) > 0

	// Collect Pydantic schema imports for input validation (only when validate=false).
	// When validate=true we use the zero-dep validators instead.
	seen := make(map[string]bool)
	var schemaImports []string
	if !opts.Validate {
		for _, act := range mod.Actions {
			if act.Input != "" && !seen[act.Input] {
				seen[act.Input] = true
				schemaImports = append(schemaImports, act.Input+"Schema")
			}
		}
	}

	var sb strings.Builder
	sb.WriteString("# AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")

	// Framework-specific imports.
	for _, imp := range strat.RouterImports(moduleLower) {
		sb.WriteString(imp + "\n")
	}

	if hasMiddleware {
		sb.WriteString(fmt.Sprintf("from ..middleware.i_%s_middleware import I%sMiddleware\n", moduleLower, mod.Name))
	}
	sb.WriteString(fmt.Sprintf("from ..interfaces.i_%s_service import I%sService\n", moduleLower, mod.Name))

	if len(schemaImports) > 0 {
		sb.WriteString(fmt.Sprintf("from ..schemas.schemas import %s\n", strings.Join(schemaImports, ", ")))
	}

	// When validation is enabled, import the generated zero-dep validators.
	if opts.Validate {
		if imports := buildPyValidatorImports(mod); len(imports) > 0 {
			sb.WriteString(fmt.Sprintf("from .._validators import %s\n", strings.Join(imports, ", ")))
		}
	}

	sb.WriteString("\n")

	if hasMiddleware {
		sb.WriteString(fmt.Sprintf("def register_%s_routes(app, service: I%sService, middleware: I%sMiddleware) -> None:\n", moduleLower, mod.Name, mod.Name))
	} else {
		sb.WriteString(fmt.Sprintf("def register_%s_routes(app, service: I%sService) -> None:\n", moduleLower, mod.Name))
	}
	if mod.Description != "" {
		sb.WriteString(fmt.Sprintf("    \"\"\"%s\"\"\"\n", mod.Description))
	}

	for _, act := range mod.Actions {
		if act.Method == "WS" {
			routePath := act.Path
			if mod.Prefix != "" {
				routePath = mod.Prefix + act.Path
			}
			pathParams := emitter.ExtractPathParams(routePath)
			actionName := emitter.ToSnakeCase(act.Name)
			if act.Description != "" {
				sb.WriteString(fmt.Sprintf("\n    # %s\n", act.Description))
			}
			sb.WriteString(strat.WSHandlerCode(actionName, routePath, act.Stream, act.Emit, pathParams))
		} else {
			writeRouteHandler(&sb, mod, moduleLower, act, opts, strat)
		}
	}
	sb.WriteString("\n")

	return os.WriteFile(filepath.Join(dir, moduleLower+"_routes.py"), []byte(sb.String()), 0644)
}

// writeRouteHandler appends the route registration for a single action using the given strategy.
func writeRouteHandler(sb *strings.Builder, mod ast.Module, moduleLower string, act ast.Action, opts emitter.EmitOptions, strat pystrategy.PythonFrameworkStrategy) {
	fnName := fmt.Sprintf("%s_%s", moduleLower, emitter.ToSnakeCase(act.Name))
	routePath := act.Path
	if mod.Prefix != "" {
		routePath = mod.Prefix + act.Path
	}

	pathParams := emitter.ExtractPathParams(routePath)
	flaskPath := emitter.ToFlaskPath(routePath)

	if act.Description != "" {
		sb.WriteString(fmt.Sprintf("\n    # %s\n", act.Description))
	}

	if len(pathParams) > 0 {
		pyParams := make([]string, len(pathParams))
		for i, p := range pathParams {
			pyParams[i] = emitter.ToSnakeCase(p)
		}
		sb.WriteString(fmt.Sprintf("\n    def %s(%s):\n", fnName, strings.Join(pyParams, ", ")))
	} else {
		sb.WriteString(fmt.Sprintf("\n    def %s():\n", fnName))
	}

	sb.WriteString("        try:\n")

	// ── Build service call arguments ─────────────────────────────────────────
	callArgs := make([]string, 0, len(pathParams)+2)
	for _, p := range pathParams {
		callArgs = append(callArgs, emitter.ToSnakeCase(p))
	}

	if act.Input != "" {
		if opts.Validate {
			// Use generated zero-dep validator: parses and validates, raises 400 on failure.
			inputFn := "parse_" + emitter.ToSnakeCase(act.Input)
			rawRead := strat.ExtractBody(act.Input)
			sb.WriteString(fmt.Sprintf("            body = %s(%s)\n", inputFn, rawRead))
			callArgs = append(callArgs, "body")
		} else {
			// Fallback: Pydantic schema validation (requires pydantic installed).
			sb.WriteString(fmt.Sprintf("            input = %sSchema(**%s).model_dump()\n", act.Input, strat.ExtractBody(act.Input+"Schema")))
			callArgs = append(callArgs, "input")
		}
	}

	if act.Query != "" {
		callArgs = append(callArgs, "request.args.to_dict()")
	}

	if act.Headers != "" {
		sb.WriteString("            headers = {\n")
		sb.WriteString(fmt.Sprintf("                # Extracted from request headers for %s\n", act.Headers))
		sb.WriteString("            }\n")
		callArgs = append(callArgs, "headers")
	}

	serviceCallStr := fmt.Sprintf("service.%s(%s)", emitter.ToSnakeCase(act.Name), strings.Join(callArgs, ", "))

	// ── Service call + optional output assertion + response ──────────────────
	switch {
	case act.Method == "DELETE" && act.Output == "":
		sb.WriteString(fmt.Sprintf("            %s\n", serviceCallStr))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnNoContent()))

	case act.Method == "POST":
		sb.WriteString(fmt.Sprintf("            result = %s\n", serviceCallStr))
		if opts.Validate && act.Output != "" {
			writePyOutputAssertion(sb, act)
		}
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnCreated("result")))

	default:
		sb.WriteString(fmt.Sprintf("            result = %s\n", serviceCallStr))
		if opts.Validate && act.Output != "" {
			writePyOutputAssertion(sb, act)
		}
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnOk("result")))
	}

	// Catch block: handles VeldValidationError (400), VeldContractError (500), and service errors.
	sb.WriteString("        except Exception as e:\n")
	sb.WriteString("            status = getattr(e, 'status', getattr(e, 'status_code', 500))\n")
	sb.WriteString("            body = {'error': str(e)}\n")
	sb.WriteString("            if hasattr(e, 'code'):\n")
	sb.WriteString("                body['code'] = e.code\n")
	sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnError("status", "body")))

	// Apply middleware decorators in reverse order (innermost first).
	for i := len(act.Middleware) - 1; i >= 0; i-- {
		mw := act.Middleware[i]
		sb.WriteString(fmt.Sprintf("    %s = middleware.%s(%s)\n", fnName, emitter.ToSnakeCase(mw), fnName))
	}

	methods := fmt.Sprintf("['%s']", strings.ToUpper(act.Method))
	sb.WriteString(fmt.Sprintf("    %s\n", strat.RegisterRoute(moduleLower, fnName, flaskPath, methods)))
}

// writePyOutputAssertion emits assert_x(result) or assert_x_list(result).
func writePyOutputAssertion(sb *strings.Builder, act ast.Action) {
	if act.OutputArray {
		sb.WriteString(fmt.Sprintf("            assert_%s_list(result)\n", emitter.ToSnakeCase(act.Output)))
	} else {
		sb.WriteString(fmt.Sprintf("            assert_%s(result)\n", emitter.ToSnakeCase(act.Output)))
	}
}

// emitMiddlewareProtocol writes interfaces/i_{module}_middleware.py.
func (e *PythonEmitter) emitMiddlewareProtocol(mod ast.Module, outDir string) error {
	allMiddleware := emitter.CollectModuleMiddleware(mod)
	if len(allMiddleware) == 0 {
		return nil
	}

	dir := filepath.Join(outDir, "middleware")
	moduleLower := strings.ToLower(mod.Name)

	var sb strings.Builder
	sb.WriteString("# AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("from typing import Callable, Protocol\n\n\n")
	sb.WriteString(fmt.Sprintf("class I%sMiddleware(Protocol):\n", mod.Name))
	sb.WriteString(fmt.Sprintf("    \"\"\"Middleware protocol for the %s module.\n", mod.Name))
	sb.WriteString("    Implement this class and pass it to the route registrar.\n    \"\"\"\n\n")

	for _, mw := range allMiddleware {
		snakeMw := emitter.ToSnakeCase(mw)
		sb.WriteString(fmt.Sprintf("    def %s(self, handler: Callable) -> Callable:\n", snakeMw))
		sb.WriteString(fmt.Sprintf("        \"\"\"Wrap the handler with %s middleware.\"\"\"\n", mw))
		sb.WriteString("        ...\n\n")
	}

	return os.WriteFile(filepath.Join(dir, "i_"+moduleLower+"_middleware.py"), []byte(sb.String()), 0644)
}

package python

// routes.go — emits routes/{module}_routes.py with try/except and
// correct HTTP status codes (201 for POST, 204 for DELETE with no output).
//
// When EmitOptions.Validate is true, route handlers are augmented with:
//   - parse_x(body)   — validates input shape before passing to service (→ 400)
//   - assert_x(result) — guards output shape before sending to client   (→ 500)

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	pystrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/python/strategy"
)

func (e *PythonEmitter) emitRoutes(mod ast.Module, outDir string, opts emitter.EmitOptions, strat pystrategy.PythonFrameworkStrategy) error {
	dir := filepath.Join(outDir, "routes")
	moduleLower := strings.ToLower(mod.Name)

	allMiddleware := emitter.CollectModuleMiddleware(mod)
	hasMiddleware := len(allMiddleware) > 0

	// Collect Pydantic schema imports for input validation (only when validate=false).
	// When validate=true we use the zero-dep validators instead.
	seen := make(map[string]bool)
	var schemaImports []string
	if !opts.Validate {
		for _, act := range mod.Actions {
			if act.Input != "" && !seen[act.Input] {
				seen[act.Input] = true
				schemaImports = append(schemaImports, act.Input+"Schema")
			}
		}
	}

	var sb strings.Builder
	sb.WriteString("# AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")

	// Framework-specific imports.
	for _, imp := range strat.RouterImports(moduleLower) {
		sb.WriteString(imp + "\n")
	}

	if hasMiddleware {
		sb.WriteString(fmt.Sprintf("from ..middleware.i_%s_middleware import I%sMiddleware\n", moduleLower, mod.Name))
	}
	sb.WriteString(fmt.Sprintf("from ..interfaces.i_%s_service import I%sService\n", moduleLower, mod.Name))

	if len(schemaImports) > 0 {
		sb.WriteString(fmt.Sprintf("from ..schemas.schemas import %s\n", strings.Join(schemaImports, ", ")))
	}

	// When validation is enabled, import the generated zero-dep validators.
	if opts.Validate {
		if imports := buildPyValidatorImports(mod); len(imports) > 0 {
			sb.WriteString(fmt.Sprintf("from .._validators import %s\n", strings.Join(imports, ", ")))
		}
	}

	sb.WriteString("\n")

	if hasMiddleware {
		sb.WriteString(fmt.Sprintf("def register_%s_routes(app, service: I%sService, middleware: I%sMiddleware) -> None:\n", moduleLower, mod.Name, mod.Name))
	} else {
		sb.WriteString(fmt.Sprintf("def register_%s_routes(app, service: I%sService) -> None:\n", moduleLower, mod.Name))
	}
	if mod.Description != "" {
		sb.WriteString(fmt.Sprintf("    \"\"\"%s\"\"\"\n", mod.Description))
	}

	for _, act := range mod.Actions {
		if act.Method == "WS" {
			routePath := act.Path
			if mod.Prefix != "" {
				routePath = mod.Prefix + act.Path
			}
			pathParams := emitter.ExtractPathParams(routePath)
			actionName := emitter.ToSnakeCase(act.Name)
			if act.Description != "" {
				sb.WriteString(fmt.Sprintf("\n    # %s\n", act.Description))
			}
			sb.WriteString(strat.WSHandlerCode(actionName, routePath, act.Stream, act.Emit, pathParams))
		} else {
			writeRouteHandler(&sb, mod, moduleLower, act, opts, strat)
		}
	}
	sb.WriteString("\n")

	return os.WriteFile(filepath.Join(dir, moduleLower+"_routes.py"), []byte(sb.String()), 0644)
}

// writeRouteHandler appends the route registration for a single action using the given strategy.
func writeRouteHandler(sb *strings.Builder, mod ast.Module, moduleLower string, act ast.Action, opts emitter.EmitOptions, strat pystrategy.PythonFrameworkStrategy) {
	fnName := fmt.Sprintf("%s_%s", moduleLower, emitter.ToSnakeCase(act.Name))
	routePath := act.Path
	if mod.Prefix != "" {
		routePath = mod.Prefix + act.Path
	}

	pathParams := emitter.ExtractPathParams(routePath)
	flaskPath := emitter.ToFlaskPath(routePath)

	if act.Description != "" {
		sb.WriteString(fmt.Sprintf("\n    # %s\n", act.Description))
	}

	if len(pathParams) > 0 {
		pyParams := make([]string, len(pathParams))
		for i, p := range pathParams {
			pyParams[i] = emitter.ToSnakeCase(p)
		}
		sb.WriteString(fmt.Sprintf("\n    def %s(%s):\n", fnName, strings.Join(pyParams, ", ")))
	} else {
		sb.WriteString(fmt.Sprintf("\n    def %s():\n", fnName))
	}

	sb.WriteString("        try:\n")

	// ── Build service call arguments ─────────────────────────────────────────
	callArgs := make([]string, 0, len(pathParams)+2)
	for _, p := range pathParams {
		callArgs = append(callArgs, emitter.ToSnakeCase(p))
	}

	if act.Input != "" {
		if opts.Validate {
			// Use generated zero-dep validator: parses and validates, raises 400 on failure.
			inputFn := "parse_" + emitter.ToSnakeCase(act.Input)
			rawRead := strat.ExtractBody(act.Input)
			sb.WriteString(fmt.Sprintf("            body = %s(%s)\n", inputFn, rawRead))
			callArgs = append(callArgs, "body")
		} else {
			// Fallback: Pydantic schema validation (requires pydantic installed).
			sb.WriteString(fmt.Sprintf("            input = %sSchema(**%s).model_dump()\n", act.Input, strat.ExtractBody(act.Input+"Schema")))
			callArgs = append(callArgs, "input")
		}
	}

	if act.Query != "" {
		callArgs = append(callArgs, "request.args.to_dict()")
	}

	if act.Headers != "" {
		sb.WriteString("            headers = {\n")
		sb.WriteString(fmt.Sprintf("                # Extracted from request headers for %s\n", act.Headers))
		sb.WriteString("            }\n")
		callArgs = append(callArgs, "headers")
	}

	serviceCallStr := fmt.Sprintf("service.%s(%s)", emitter.ToSnakeCase(act.Name), strings.Join(callArgs, ", "))

	// ── Service call + optional output assertion + response ──────────────────
	statusCode := emitter.SuccessStatusForAction(act)
	switch {
	case statusCode == 204:
		sb.WriteString(fmt.Sprintf("            %s\n", serviceCallStr))
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnNoContent()))

	case statusCode == 200:
		sb.WriteString(fmt.Sprintf("            result = %s\n", serviceCallStr))
		if opts.Validate && act.Output != "" {
			writePyOutputAssertion(sb, act)
		}
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnOk("result")))

	case statusCode == 201:
		sb.WriteString(fmt.Sprintf("            result = %s\n", serviceCallStr))
		if opts.Validate && act.Output != "" {
			writePyOutputAssertion(sb, act)
		}
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnCreated("result")))

	default:
		sb.WriteString(fmt.Sprintf("            result = %s\n", serviceCallStr))
		if opts.Validate && act.Output != "" {
			writePyOutputAssertion(sb, act)
		}
		sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnError(fmt.Sprintf("%d", statusCode), "result")))
	}

	// Catch block: handles VeldValidationError (400), VeldContractError (500), and service errors.
	sb.WriteString("        except Exception as e:\n")
	sb.WriteString("            status = getattr(e, 'status', getattr(e, 'status_code', 500))\n")
	sb.WriteString("            body = {'error': str(e)}\n")
	sb.WriteString("            if hasattr(e, 'code'):\n")
	sb.WriteString("                body['code'] = e.code\n")
	sb.WriteString(fmt.Sprintf("            %s\n", strat.ReturnError("status", "body")))

	// Apply middleware decorators in reverse order (innermost first).
	for i := len(act.Middleware) - 1; i >= 0; i-- {
		mw := act.Middleware[i]
		sb.WriteString(fmt.Sprintf("    %s = middleware.%s(%s)\n", fnName, emitter.ToSnakeCase(mw), fnName))
	}

	methods := fmt.Sprintf("['%s']", strings.ToUpper(act.Method))
	sb.WriteString(fmt.Sprintf("    %s\n", strat.RegisterRoute(moduleLower, fnName, flaskPath, methods)))
}

// writePyOutputAssertion emits assert_x(result) or assert_x_list(result).
func writePyOutputAssertion(sb *strings.Builder, act ast.Action) {
	if act.OutputArray {
		sb.WriteString(fmt.Sprintf("            assert_%s_list(result)\n", emitter.ToSnakeCase(act.Output)))
	} else {
		sb.WriteString(fmt.Sprintf("            assert_%s(result)\n", emitter.ToSnakeCase(act.Output)))
	}
}

// emitMiddlewareProtocol writes interfaces/i_{module}_middleware.py.
func (e *PythonEmitter) emitMiddlewareProtocol(mod ast.Module, outDir string) error {
	allMiddleware := emitter.CollectModuleMiddleware(mod)
	if len(allMiddleware) == 0 {
		return nil
	}

	dir := filepath.Join(outDir, "middleware")
	moduleLower := strings.ToLower(mod.Name)

	var sb strings.Builder
	sb.WriteString("# AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("from typing import Callable, Protocol\n\n\n")
	sb.WriteString(fmt.Sprintf("class I%sMiddleware(Protocol):\n", mod.Name))
	sb.WriteString(fmt.Sprintf("    \"\"\"Middleware protocol for the %s module.\n", mod.Name))
	sb.WriteString("    Implement this class and pass it to the route registrar.\n    \"\"\"\n\n")

	for _, mw := range allMiddleware {
		snakeMw := emitter.ToSnakeCase(mw)
		sb.WriteString(fmt.Sprintf("    def %s(self, handler: Callable) -> Callable:\n", snakeMw))
		sb.WriteString(fmt.Sprintf("        \"\"\"Wrap the handler with %s middleware.\"\"\"\n", mw))
		sb.WriteString("        ...\n\n")
	}

	return os.WriteFile(filepath.Join(dir, "i_"+moduleLower+"_middleware.py"), []byte(sb.String()), 0644)
}

// routes.go - Route handler generation for Rust backend
package rustbackend

import (
	"fmt"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	ruststrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/rust/strategy"
	"github.com/Adhamzineldin/Veld/internal/emitter/codegen"
	"github.com/Adhamzineldin/Veld/internal/emitter/lang"
)

// generateRouter writes src/router.rs with the framework router setup.
func (e *RustEmitter) generateRouter(a ast.AST, strat ruststrategy.RustFrameworkStrategy) []byte {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	// Emit router imports from the strategy.
	for _, imp := range strat.RouterImports() {
		w.Writeln(fmt.Sprintf("use %s;", imp))
	}
	if len(strat.RouterImports()) > 0 {
		w.BlankLine()
	}

	for _, mod := range a.Modules {
		modName := e.adapter.NamingConvention(mod.Name, lang.NamingContextPrivate)
		w.Writeln(fmt.Sprintf("use crate::%s::router as %s_router;", modName, modName))
	}
	w.BlankLine()

	w.Writeln("/// Build the complete router with all module routes.")
	w.Writeln("pub fn build_router() -> impl std::any::Any {")
	w.Indent()

	// Collect route entries for strategy (WS actions use "GET" for the upgrade request).
	var routes []ruststrategy.RouteEntry
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			method := act.Method
			if method == "WS" {
				method = "GET" // WebSocket upgrade is always a GET request
			}
			routes = append(routes, ruststrategy.RouteEntry{
				Method:  method,
				Path:    fullAxumPath(mod, act),
				Handler: e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate),
			})
		}
	}

	routerCode := strat.BuildRouter(routes)
	if routerCode != "" {
		w.Writeln(routerCode)
	} else {
		// Plain strategy: merge module sub-routers if available.
		if len(a.Modules) == 0 {
			w.Writeln("()")
		} else {
			parts := make([]string, len(a.Modules))
			for i, mod := range a.Modules {
				modName := e.adapter.NamingConvention(mod.Name, lang.NamingContextPrivate)
				parts[i] = fmt.Sprintf("%s_router()", modName)
			}
			w.Writeln(parts[0])
			for _, p := range parts[1:] {
				w.Writeln(fmt.Sprintf("    .merge(%s)", p))
			}
		}
	}

	w.Dedent()
	w.Writeln("}")
	return w.Bytes()
}

// generateModuleRoutes writes src/{module}/mod.rs with handlers for one module.
func (e *RustEmitter) generateModuleRoutes(a ast.AST, mod ast.Module, strat ruststrategy.RustFrameworkStrategy) ([]byte, error) {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	// Framework-specific handler imports.
	handlerImports := strat.HandlerImports()
	if len(handlerImports) > 0 {
		// First entry may be a multi-line block opener (e.g. "use axum::{")
		w.Writeln("use " + handlerImports[0])
		for _, imp := range handlerImports[1:] {
			w.Writeln(imp)
		}
	}
	w.BlankLine()
	w.Writeln("use crate::models::*;")
	w.Writeln(fmt.Sprintf("use crate::services::%sService;", e.adapter.NamingConvention(mod.Name, lang.NamingContextExported)))
	w.BlankLine()

	// router() function.
	w.Writeln(fmt.Sprintf("/// Build the sub-router for the %s module.", mod.Name))
	w.Writeln("pub fn router<S>() -> impl std::any::Any")
	w.Writeln("where")
	w.Indent()
	w.Writeln(fmt.Sprintf("S: %sService + Clone + Send + Sync + 'static,", e.adapter.NamingConvention(mod.Name, lang.NamingContextExported)))
	w.Dedent()
	w.WriteBlock("{")

	// Build route entries from this module (skip WS — handled separately).
	var routes []ruststrategy.RouteEntry
	for _, act := range mod.Actions {
		if act.Method == "WS" {
			continue
		}
		routePath := fullAxumPath(mod, act)
		handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
		routes = append(routes, ruststrategy.RouteEntry{
			Method:  act.Method,
			Path:    routePath,
			Handler: handlerName,
		})
	}

	routerCode := strat.BuildRouter(routes)
	if routerCode != "" {
		w.Writeln(routerCode)
	} else {
		w.Writeln("()")
	}

	w.Dedent()
	w.Writeln("}")
	w.BlankLine()

	// Handler functions (HTTP) and WS handler stubs.
	for _, act := range mod.Actions {
		w.BlankLine()
		if act.Method == "WS" {
			routePath := fullAxumPath(mod, act)
			handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
			serviceName := e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
			pathParams := emitter.ExtractPathParams(routePath)
			wsCode := strat.WSHandlerCode(handlerName, routePath, serviceName, act.Stream, act.Emit, pathParams)
			for _, line := range strings.Split(strings.TrimRight(wsCode, "\n"), "\n") {
				w.Writeln(line)
			}
		} else {
			if err := e.writeHandler(w, mod, act, strat); err != nil {
				return nil, err
			}
		}
	}

	return w.Bytes(), nil
}

// writeHandler generates a single async handler function.
func (e *RustEmitter) writeHandler(w *codegen.Writer, mod ast.Module, act ast.Action, strat ruststrategy.RustFrameworkStrategy) error {
	handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	methodName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	serviceName := e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
	routePath := fullAxumPath(mod, act)
	pathParams := emitter.ExtractPathParams(routePath)

	hasInput := act.Input != ""
	hasOutput := act.Output != ""

	// Build the function signature parameters.
	var sigParams []string
	sigParams = append(sigParams, fmt.Sprintf("State(svc): State<Arc<dyn %s>>", serviceName))

	if len(pathParams) > 0 {
		if len(pathParams) == 1 {
			paramType := "String"
			sigParams = append(sigParams, fmt.Sprintf("Path(%s): Path<%s>", rustParamName(e, pathParams[0]), paramType))
		} else {
			types := make([]string, len(pathParams))
			names := make([]string, len(pathParams))
			for i, p := range pathParams {
				types[i] = "String"
				names[i] = rustParamName(e, p)
			}
			sigParams = append(sigParams, fmt.Sprintf("Path((%s)): Path<(%s)>", strings.Join(names, ", "), strings.Join(types, ", ")))
		}
	}

	if hasInput {
		sigParams = append(sigParams, fmt.Sprintf("Json(payload): Json<%s>", e.adapter.NamingConvention(act.Input, lang.NamingContextExported)))
	}

	// Return type.
	var returnType string
	if hasOutput {
		outputType := e.adapter.NamingConvention(act.Output, lang.NamingContextExported)
		if act.OutputArray {
			returnType = fmt.Sprintf("Result<(StatusCode, Json<Vec<%s>>), (StatusCode, Json<serde_json::Value>)>", outputType)
		} else {
			returnType = fmt.Sprintf("Result<(StatusCode, Json<%s>), (StatusCode, Json<serde_json::Value>)>", outputType)
		}
	} else {
		returnType = "Result<StatusCode, (StatusCode, Json<serde_json::Value>)>"
	}

	if act.Description != "" {
		w.Writeln(fmt.Sprintf("/// %s", act.Description))
	} else {
		w.Writeln(fmt.Sprintf("/// Handle %s %s.", strings.ToUpper(act.Method), routePath))
	}

	w.WriteBlock(fmt.Sprintf("pub async fn %s(%s) -> %s {", handlerName, strings.Join(sigParams, ", "), returnType))

	// Build service call arguments.
	var callArgs []string
	for _, p := range pathParams {
		callArgs = append(callArgs, rustParamName(e, p))
	}
	if hasInput {
		callArgs = append(callArgs, "payload")
	}
	if act.Headers != "" {
		// TODO: extract headers from axum HeaderMap once full Axum extractor is wired
		callArgs = append(callArgs, fmt.Sprintf("%s::default()", e.adapter.NamingConvention(act.Headers, lang.NamingContextExported)))
	}

	serviceCallExpr := fmt.Sprintf("svc.%s(%s).await", methodName, strings.Join(callArgs, ", "))
	wrapped := strat.WrapHandler(act.Method, returnType, serviceCallExpr)

	// Error helper closure (only needed when the strategy generates response code).
	if wrapped != serviceCallExpr {
		w.Writeln("let err_response = |e: String| {")
		w.Indent()
		w.Writeln("(StatusCode::INTERNAL_SERVER_ERROR, Json(serde_json::json!({\"error\": e})))")
		w.Dedent()
		w.Writeln("};")
		w.BlankLine()
	}

	for _, line := range strings.Split(wrapped, "\n") {
		w.Writeln(line)
	}

	w.Dedent()
	w.Writeln("}")
	return nil
}

// generateServices writes src/services.rs with async trait definitions.
func (e *RustEmitter) generateServices(a ast.AST) ([]byte, error) {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	w.Writeln("use async_trait::async_trait;")
	w.BlankLine()
	w.Writeln("use crate::models::*;")
	w.BlankLine()

	for _, mod := range a.Modules {
		serviceName := e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
		w.Writeln(fmt.Sprintf("/// %sService defines the contract for %s business logic.", e.adapter.NamingConvention(mod.Name, lang.NamingContextExported), mod.Name))
		w.Writeln("/// Implement this trait in your application code.")
		w.Writeln("#[async_trait]")
		w.WriteBlock(fmt.Sprintf("pub trait %s: Send + Sync {", serviceName))

		for _, act := range mod.Actions {
			if act.Method == "WS" {
				e.writeWSTraitMethods(w, mod, act)
				continue
			}
			sig, err := e.buildTraitMethod(mod, act)
			if err != nil {
				return nil, err
			}
			if act.Description != "" {
				w.Writeln(fmt.Sprintf("    /// %s", act.Description))
			}
			for _, errName := range act.Errors {
				code := emitter.ErrorCode(act.Name, errName)
				w.Writeln(fmt.Sprintf("    /// # Errors\n    /// Returns `%sError::%s` — %s", act.Name, emitter.ToCamelCase(errName), code))
			}
			w.Writeln(sig)
		}

		w.Dedent()
		w.Writeln("}")
		w.BlankLine()
	}

	return w.Bytes(), nil
}

// writeWSTraitMethods appends WS lifecycle trait methods for a WS action to w.
func (e *RustEmitter) writeWSTraitMethods(w *codegen.Writer, mod ast.Module, act ast.Action) {
	methodName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	routePath := fullAxumPath(mod, act)
	pathParams := emitter.ExtractPathParams(routePath)

	// on_{action}_connect
	var connectParams []string
	connectParams = append(connectParams, "&self")
	connectParams = append(connectParams, "socket: axum::extract::ws::WebSocket")
	for _, p := range pathParams {
		connectParams = append(connectParams, fmt.Sprintf("%s: String", rustParamName(e, p)))
	}
	if act.Description != "" {
		w.Writeln(fmt.Sprintf("    /// %s — called on WebSocket connect.", act.Description))
	} else {
		w.Writeln(fmt.Sprintf("    /// Called when a client opens the WS %s connection.", routePath))
	}
	w.Writeln(fmt.Sprintf("    async fn on_%s_connect(%s) -> Result<(), Box<dyn std::error::Error>>;", methodName, strings.Join(connectParams, ", ")))

	// on_{action}_message — only when emit type is set
	if act.Emit != "" {
		emitType := mapRustOutputType(e, act.Emit)
		w.Writeln(fmt.Sprintf("    /// Called when a client sends a %s message.", act.Emit))
		w.Writeln(fmt.Sprintf("    async fn on_%s_message(&self, socket: &mut axum::extract::ws::WebSocket, msg: %s) -> Result<(), Box<dyn std::error::Error>>;", methodName, emitType))
	}

	// on_{action}_close — always included
	w.Writeln(fmt.Sprintf("    /// Called when the WS %s connection is closed.", routePath))
	w.Writeln(fmt.Sprintf("    async fn on_%s_close(&self, socket: axum::extract::ws::WebSocket) -> Result<(), Box<dyn std::error::Error>>;", methodName))
}

// buildTraitMethod builds the async trait method signature for an action.
func (e *RustEmitter) buildTraitMethod(mod ast.Module, act ast.Action) (string, error) {
	methodName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	routePath := fullAxumPath(mod, act)
	pathParams := emitter.ExtractPathParams(routePath)

	var params []string
	params = append(params, "&self")

	for _, p := range pathParams {
		params = append(params, fmt.Sprintf("%s: String", rustParamName(e, p)))
	}
	if act.Input != "" {
		inputType := e.adapter.NamingConvention(act.Input, lang.NamingContextExported)
		params = append(params, fmt.Sprintf("input: %s", inputType))
	}
	if act.Headers != "" {
		headersType := e.adapter.NamingConvention(act.Headers, lang.NamingContextExported)
		params = append(params, fmt.Sprintf("headers: %s", headersType))
	}

	returnType := buildRustReturnType(e, act)
	return fmt.Sprintf("    async fn %s(%s) -> %s;", methodName, strings.Join(params, ", "), returnType), nil
}

// buildRustReturnType returns the Result type for a trait method.
func buildRustReturnType(e *RustEmitter, act ast.Action) string {
	if act.Output == "" {
		return "Result<(), Box<dyn std::error::Error>>"
	}
	outputType := mapRustOutputType(e, act.Output)
	if act.OutputArray {
		return fmt.Sprintf("Result<Vec<%s>, Box<dyn std::error::Error>>", outputType)
	}
	return fmt.Sprintf("Result<%s, Box<dyn std::error::Error>>", outputType)
}

// mapRustOutputType maps a Veld output type to its Rust equivalent.
func mapRustOutputType(e *RustEmitter, t string) string {
	switch t {
	case "string", "uuid", "date", "datetime", "decimal":
		return "String"
	case "int":
		return "i32"
	case "float":
		return "f64"
	case "bool":
		return "bool"
	case "any", "json":
		return "serde_json::Value"
	default:
		return e.adapter.NamingConvention(t, lang.NamingContextExported)
	}
}

// ── helpers ───────────────────────────────────────────────────────────────────

// fullAxumPath joins the module prefix and action path, converting :param to :param
// (Axum uses the same `:param` syntax as Veld — no conversion needed).
func fullAxumPath(mod ast.Module, act ast.Action) string {
	if mod.Prefix != "" {
		return mod.Prefix + act.Path
	}
	return act.Path
}

// axumMethod maps a Veld HTTP method to the Axum routing function name.
func axumMethod(method string) string {
	switch strings.ToUpper(method) {
	case "GET":
		return "get"
	case "POST":
		return "post"
	case "PUT":
		return "put"
	case "DELETE":
		return "delete"
	case "PATCH":
		return "patch"
	default:
		return "get"
	}
}

// successStatusCode returns the Axum StatusCode constant for a successful response.
func successStatusCode(act ast.Action) string {
	if strings.ToUpper(act.Method) == "POST" {
		return "StatusCode::CREATED"
	}
	return "StatusCode::OK"
}

// rustParamName converts a path param name to a Rust snake_case variable name.
func rustParamName(e *RustEmitter, param string) string {
	return e.adapter.NamingConvention(param, lang.NamingContextPrivate)
}

// routes.go - Route handler generation for Rust backend
package rustbackend

import (
	"fmt"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
	ruststrategy "github.com/Adhamzineldin/Veld/internal/emitter/backend/rust/strategy"
	"github.com/Adhamzineldin/Veld/internal/emitter/codegen"
	"github.com/Adhamzineldin/Veld/internal/emitter/lang"
)

// generateRouter writes src/router.rs with the framework router setup.
func (e *RustEmitter) generateRouter(a ast.AST, strat ruststrategy.RustFrameworkStrategy) []byte {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	// Emit router imports from the strategy.
	for _, imp := range strat.RouterImports() {
		w.Writeln(fmt.Sprintf("use %s;", imp))
	}
	if len(strat.RouterImports()) > 0 {
		w.BlankLine()
	}

	for _, mod := range a.Modules {
		modName := e.adapter.NamingConvention(mod.Name, lang.NamingContextPrivate)
		w.Writeln(fmt.Sprintf("use crate::%s::router as %s_router;", modName, modName))
	}
	w.BlankLine()

	w.Writeln("/// Build the complete router with all module routes.")
	w.Writeln("pub fn build_router() -> impl std::any::Any {")
	w.Indent()

	// Collect route entries for strategy (WS actions use "GET" for the upgrade request).
	var routes []ruststrategy.RouteEntry
	for _, mod := range a.Modules {
		for _, act := range mod.Actions {
			method := act.Method
			if method == "WS" {
				method = "GET" // WebSocket upgrade is always a GET request
			}
			routes = append(routes, ruststrategy.RouteEntry{
				Method:  method,
				Path:    fullAxumPath(mod, act),
				Handler: e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate),
			})
		}
	}

	routerCode := strat.BuildRouter(routes)
	if routerCode != "" {
		w.Writeln(routerCode)
	} else {
		// Plain strategy: merge module sub-routers if available.
		if len(a.Modules) == 0 {
			w.Writeln("()")
		} else {
			parts := make([]string, len(a.Modules))
			for i, mod := range a.Modules {
				modName := e.adapter.NamingConvention(mod.Name, lang.NamingContextPrivate)
				parts[i] = fmt.Sprintf("%s_router()", modName)
			}
			w.Writeln(parts[0])
			for _, p := range parts[1:] {
				w.Writeln(fmt.Sprintf("    .merge(%s)", p))
			}
		}
	}

	w.Dedent()
	w.Writeln("}")
	return w.Bytes()
}

// generateModuleRoutes writes src/{module}/mod.rs with handlers for one module.
func (e *RustEmitter) generateModuleRoutes(a ast.AST, mod ast.Module, strat ruststrategy.RustFrameworkStrategy) ([]byte, error) {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	// Framework-specific handler imports.
	handlerImports := strat.HandlerImports()
	if len(handlerImports) > 0 {
		// First entry may be a multi-line block opener (e.g. "use axum::{")
		w.Writeln("use " + handlerImports[0])
		for _, imp := range handlerImports[1:] {
			w.Writeln(imp)
		}
	}
	w.BlankLine()
	w.Writeln("use crate::models::*;")
	w.Writeln(fmt.Sprintf("use crate::services::%sService;", e.adapter.NamingConvention(mod.Name, lang.NamingContextExported)))
	w.BlankLine()

	// router() function.
	w.Writeln(fmt.Sprintf("/// Build the sub-router for the %s module.", mod.Name))
	w.Writeln("pub fn router<S>() -> impl std::any::Any")
	w.Writeln("where")
	w.Indent()
	w.Writeln(fmt.Sprintf("S: %sService + Clone + Send + Sync + 'static,", e.adapter.NamingConvention(mod.Name, lang.NamingContextExported)))
	w.Dedent()
	w.WriteBlock("{")

	// Build route entries from this module (skip WS — handled separately).
	var routes []ruststrategy.RouteEntry
	for _, act := range mod.Actions {
		if act.Method == "WS" {
			continue
		}
		routePath := fullAxumPath(mod, act)
		handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
		routes = append(routes, ruststrategy.RouteEntry{
			Method:  act.Method,
			Path:    routePath,
			Handler: handlerName,
		})
	}

	routerCode := strat.BuildRouter(routes)
	if routerCode != "" {
		w.Writeln(routerCode)
	} else {
		w.Writeln("()")
	}

	w.Dedent()
	w.Writeln("}")
	w.BlankLine()

	// Handler functions (HTTP) and WS handler stubs.
	for _, act := range mod.Actions {
		w.BlankLine()
		if act.Method == "WS" {
			routePath := fullAxumPath(mod, act)
			handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
			serviceName := e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
			pathParams := emitter.ExtractPathParams(routePath)
			wsCode := strat.WSHandlerCode(handlerName, routePath, serviceName, act.Stream, act.Emit, pathParams)
			for _, line := range strings.Split(strings.TrimRight(wsCode, "\n"), "\n") {
				w.Writeln(line)
			}
		} else {
			if err := e.writeHandler(w, mod, act, strat); err != nil {
				return nil, err
			}
		}
	}

	return w.Bytes(), nil
}

// writeHandler generates a single async handler function.
func (e *RustEmitter) writeHandler(w *codegen.Writer, mod ast.Module, act ast.Action, strat ruststrategy.RustFrameworkStrategy) error {
	handlerName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	methodName := e.adapter.NamingConvention(act.Name, lang.NamingContextPrivate)
	serviceName := e.adapter.NamingConvention(mod.Name, lang.NamingContextExported) + "Service"
	routePath := fullAxumPath(mod, act)
	pathParams := emitter.ExtractPathParams(routePath)

	hasInput := act.Input != ""
	hasOutput := act.Output != ""

	// Build the function signature parameters.
	var sigParams []string
	sigParams = append(sigParams, fmt.Sprintf("State(svc): State<Arc<dyn %s>>", serviceName))

	if len(pathParams) > 0 {
		if len(pathParams) == 1 {
			paramType := "String"
			sigParams = append(sigParams, fmt.Sprintf("Path(%s): Path<%s>", rustParamName(e, pathParams[0]), paramType))
		} else {
			types := make([]string, len(pathParams))
			names := make([]string, len(pathParams))
			for i, p := range pathParams {
				types[i] = "String"
				names[i] = rustParamName(e, p)
			}
			sigParams = append(sigParams, fmt.Sprintf("Path((%s)): Path<(%s)>", strings.Join(names, ", "), strings.Join(types, ", ")))
		}
	}

	if hasInput {
		sigParams = append(sigParams, fmt.Sprintf("Json(payload): Json<%s>", e.adapter.NamingConvention(act.Input, lang.NamingContextExported)))
	}

	// Return type.
	var returnType string
	if hasOutput {
		outputType := e.adapter.NamingConvention(act.Output, lang.NamingContextExported)
		if act.OutputArray {
			returnType = fmt.Sprintf("Result<(StatusCode, Json<Vec<%s>>), (StatusCode, Json<serde_json::Value>)>", outputType)
		} else {
			returnType = fmt.Sprintf("Result<(StatusCode, Json<%s>), (StatusCode, Json<serde_json::Value>)>", outputType)
		}
	} else {
		returnType = "Result<StatusCode, (StatusCode, Json<serde_json::Value>)>"
	}

	if act.Description != "" {
		w.Writeln(fmt.Sprintf("/// %s", act.Description))
	} else {
		w.Writeln(fmt.Sprintf("/// Handle %s %s.", strings.ToUpper(act.Method), routePath))
	}

	w.WriteBlock(fmt.Sprintf("pub async fn %s(%s) -> %s {", handlerName, strings.Join(sigParams, ", "), returnType))

	// Build service call arguments.
	var callArgs []string
	for _, p := range pathParams {
		callArgs = append(callArgs, rustParamName(e, p))
	}
	if hasInput {
		callArgs = append(callArgs, "payload")
	}
	if act.Headers != "" {
		// TODO: extract headers from axum HeaderMap once full Axum extractor is wired
		callArgs = append(callArgs, fmt.Sprintf("%s::default()", e.adapter.NamingConvention(act.Headers, lang.NamingContextExported)))
	}

	serviceCallExpr := fmt.Sprintf("svc.%s(%s).await", methodName, strings.Join(callArgs, ", "))
	wrapped := strat.WrapHandler(act.Method, returnType, serviceCallExpr, emitter.SuccessStatusForAction(act))

	// Error helper closure (only needed when the strategy generates response code).
	if wrapped != serviceCallExpr {
		w.Writeln("let err_response = |e: String| {")
		w.Indent()
		w.Writeln("(StatusCode::INTERNAL_SERVER_ERROR, Json(serde_json::json!({\"error\": e})))")
		w.Dedent()
		w.Writeln("};")
		w.BlankLine()
	}

	for _, line := range strings.Split(wrapped, "\n") {
		w.Writeln(line)
	}

	w.Dedent()
	w.Writeln("}")
	return nil
}

// generateServices writes src/services.rs with async trait definitions.
func (e *RustEmitter) generateServices(a ast.AST) ([]byte, error) {
	w := codegen.NewWriter("    ")
	w.Writeln(header)

	w.Writeln("use async_trait::async_trait;")
