func buildPaths(a ast.AST) map[string]interface{} {
	paths := make(map[string]interface{})

	for _, mod := range a.Modules {
		tag := mod.Name
		for _, act := range mod.Actions {
			routePath := act.Path
			if mod.Prefix != "" {
				routePath = mod.Prefix + act.Path
			}
			oaPath := emitter.ToOpenAPIPath(routePath)
			pathParams := emitter.ExtractPathParams(routePath)

			op := map[string]interface{}{
				"tags":        []string{tag},
				"operationId": mod.Name + "_" + act.Name,
			}
			if act.Description != "" {
				op["summary"] = act.Description
			}
			if mod.Description != "" {
				op["description"] = mod.Description
			}

			// Path parameters
			var params []map[string]interface{}
			for _, p := range pathParams {
				params = append(params, map[string]interface{}{
					"name":     p,
					"in":       "path",
					"required": true,
					"schema":   map[string]interface{}{"type": "string"},
				})
			}

			// Query parameters from query model
			if act.Query != "" {
				for _, m := range a.Models {
					if m.Name == act.Query {
						for _, f := range m.Fields {
							params = append(params, map[string]interface{}{
								"name":     f.Name,
								"in":       "query",
								"required": !f.Optional,
								"schema":   oaFieldSchema(f),
							})
						}
						break
					}
				}
			}

			if len(params) > 0 {
				op["parameters"] = params
			}

			// Request body
			if act.Input != "" {
				op["requestBody"] = map[string]interface{}{
					"required": true,
					"content": map[string]interface{}{
						"application/json": map[string]interface{}{
							"schema": map[string]interface{}{"$ref": "#/components/schemas/" + act.Input},
						},
					},
				}
			}

			// Responses
			responses := map[string]interface{}{}
			successCode := strconv.Itoa(emitter.SuccessStatusForAction(act))

			if act.Output != "" {
				outputSchema := map[string]interface{}{"$ref": "#/components/schemas/" + act.Output}
				if act.OutputArray {
					outputSchema = map[string]interface{}{
						"type":  "array",
						"items": map[string]interface{}{"$ref": "#/components/schemas/" + act.Output},
					}
				}
				responses[successCode] = map[string]interface{}{
					"description": "Success",
					"content": map[string]interface{}{
						"application/json": map[string]interface{}{
							"schema": outputSchema,
						},
					},
				}
			} else {
				responses[successCode] = map[string]interface{}{"description": "Success"}
			}

			responses["400"] = map[string]interface{}{
				"description": "Bad Request",
				"content": map[string]interface{}{
					"application/json": map[string]interface{}{
						"schema": map[string]interface{}{"$ref": "#/components/schemas/ErrorResponse"},
					},
				},
			}
			responses["500"] = map[string]interface{}{
				"description": "Internal Server Error",
				"content": map[string]interface{}{
					"application/json": map[string]interface{}{
						"schema": map[string]interface{}{"$ref": "#/components/schemas/ErrorResponse"},
					},
				},
			}

			op["responses"] = responses

			method := strings.ToLower(act.Method)
			if _, ok := paths[oaPath]; !ok {
				paths[oaPath] = make(map[string]interface{})
			}
			paths[oaPath].(map[string]interface{})[method] = op
		}
	}

	return paths
}

func buildSchemas(a ast.AST) map[string]interface{} {
	schemas := make(map[string]interface{})

	// ErrorResponse schema (standard)
	schemas["ErrorResponse"] = map[string]interface{}{
		"type":        "object",
		"description": "Standard error response",
		"properties": map[string]interface{}{
			"code":    map[string]interface{}{"type": "integer"},
			"message": map[string]interface{}{"type": "string"},
			"details": map[string]interface{}{"type": "string"},
		},
		"required": []string{"code", "message"},
	}

	// Enums
	for _, en := range a.Enums {
		s := map[string]interface{}{
			"type": "string",
			"enum": en.Values,
		}
		if en.Description != "" {
			s["description"] = en.Description
		}
		schemas[en.Name] = s
	}

	// Models
	for _, m := range a.Models {
		props := make(map[string]interface{})
		var required []string

		for _, f := range m.Fields {
			props[f.Name] = oaFieldSchema(f)
			if !f.Optional {
				required = append(required, f.Name)
			}
		}

		schema := map[string]interface{}{
			"type":       "object",
			"properties": props,
		}
		if len(required) > 0 {
			schema["required"] = required
		}
		if m.Description != "" {
			schema["description"] = m.Description
		}
		if m.Extends != "" {
			schema["allOf"] = []interface{}{
				map[string]interface{}{"$ref": "#/components/schemas/" + m.Extends},
				map[string]interface{}{
					"type":       "object",
					"properties": props,
				},
			}
			delete(schema, "type")
			delete(schema, "properties")
		}

		schemas[m.Name] = schema
	}

	return schemas
}

func oaFieldSchema(f ast.Field) map[string]interface{} {
	if f.IsMap {
		return map[string]interface{}{
			"type":                 "object",
			"additionalProperties": oaTypeSchema(f.MapValueType),
		}
	}
	if f.IsArray {
		return map[string]interface{}{
			"type":  "array",
			"items": oaTypeSchema(f.Type),
		}
	}
	return oaTypeSchema(f.Type)
}

func oaTypeSchema(t string) map[string]interface{} {
	switch t {
	case "string":
		return map[string]interface{}{"type": "string"}
	case "int":
		return map[string]interface{}{"type": "integer", "format": "int32"}
	case "float":
		return map[string]interface{}{"type": "number", "format": "double"}
	case "decimal":
		return map[string]interface{}{"type": "string", "format": "decimal"}
	case "bool":
		return map[string]interface{}{"type": "boolean"}
	case "date":
		return map[string]interface{}{"type": "string", "format": "date"}
	case "datetime":
		return map[string]interface{}{"type": "string", "format": "date-time"}
	case "long":
		return map[string]interface{}{"type": "integer", "format": "int64"}
	case "uuid":
		return map[string]interface{}{"type": "string", "format": "uuid"}
	case "bytes":
		return map[string]interface{}{"type": "string", "format": "byte"}
	case "time":
		return map[string]interface{}{"type": "string", "format": "time"}
	case "any", "json":
		return map[string]interface{}{"type": "object"}
	default:
		// Model/enum reference
		return map[string]interface{}{"$ref": "#/components/schemas/" + t}
	}
}

package lsp

import (
	"fmt"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

func computeHover(text string, pos Position, a ast.AST) *Hover {
	// ── Line-level hover for path:/prefix: directives ────────────────
	if h := hoverPathDirective(text, pos, a); h != nil {
		return h
	}
	// ── Line-level hover for @default annotations ────────────────────
	if h := hoverDefaultAnnotation(text, pos); h != nil {
		return h
	}

	word := wordAtPosition(text, pos)
	if word == "" {
		return nil
	}

	// Check models
	for _, m := range a.Models {
		if m.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**model %s**\n\n", m.Name))
			if m.Description != "" {
				sb.WriteString(m.Description + "\n\n")
			}
			if m.Extends != "" {
				sb.WriteString(fmt.Sprintf("extends `%s`\n\n", m.Extends))
			}
			sb.WriteString("Fields:\n")
			for _, f := range m.Fields {
				opt := ""
				if f.Optional {
					opt = "?"
				}
				typeStr := f.Type
				if len(f.UnionTypes) > 0 {
					typeStr = strings.Join(f.UnionTypes, " | ")
				}
				sb.WriteString(fmt.Sprintf("- `%s%s`: %s\n", f.Name, opt, typeStr))
			}
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}
	}

	// Check enums
	for _, en := range a.Enums {
		if en.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**enum %s**\n\n", en.Name))
			if en.Description != "" {
				sb.WriteString(en.Description + "\n\n")
			}
			sb.WriteString("Values: `" + strings.Join(en.Values, "`, `") + "`")
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}
	}

	// Check modules
	for _, mod := range a.Modules {
		if mod.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**module %s**\n\n", mod.Name))
			if mod.Description != "" {
				sb.WriteString(mod.Description + "\n\n")
			}
			if mod.Prefix != "" {
				sb.WriteString(fmt.Sprintf("prefix: `%s`\n\n", mod.Prefix))
			}
			sb.WriteString(fmt.Sprintf("%d action(s)\n", len(mod.Actions)))
			for _, act := range mod.Actions {
				fullPath := resolveFullPath(a.Prefix, mod.Prefix, act.Path)
				sb.WriteString(fmt.Sprintf("- `%s %s` — %s\n", act.Method, fullPath, act.Name))
			}
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}

		// Check actions
		for _, act := range mod.Actions {
			if act.Name == word {
				fullPath := resolveFullPath(a.Prefix, mod.Prefix, act.Path)
				var sb strings.Builder
				sb.WriteString(fmt.Sprintf("**action %s**\n\n", act.Name))
				if act.Description != "" {
					sb.WriteString(act.Description + "\n\n")
				}
				sb.WriteString(fmt.Sprintf("Full route: `%s %s`\n\n", act.Method, fullPath))
				if act.Input != "" {
					sb.WriteString(fmt.Sprintf("- input: `%s`\n", act.Input))
				}
				if act.Output != "" {
					out := act.Output
					if act.OutputArray {
						out += "[]"
					}
					sb.WriteString(fmt.Sprintf("- output: `%s`\n", out))
				}
				if act.Stream != "" {
					sb.WriteString(fmt.Sprintf("- stream: `%s`\n", act.Stream))
				}
				if len(act.Errors) > 0 {
					sb.WriteString(fmt.Sprintf("- errors: `%s`\n", strings.Join(act.Errors, "`, `")))
				}
				return &Hover{
					Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
				}
			}
		}
	}

	return nil
}

func wordAtPosition(text string, pos Position) string {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return ""
	}
	line := lines[pos.Line]
	if pos.Character >= len(line) {
		return ""
	}

	// Find word boundaries
	start := pos.Character
	for start > 0 && isIdentChar(line[start-1]) {
		start--
	}
	end := pos.Character
	for end < len(line) && isIdentChar(line[end]) {
		end++
	}

	if start == end {
		return ""
	}
	return line[start:end]
}

func isIdentChar(ch byte) bool {
	return (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
		(ch >= '0' && ch <= '9') || ch == '_'
}

// resolveFullPath combines app prefix + module prefix + action path into
// the full route that will be registered at runtime.
func resolveFullPath(appPrefix, modulePrefix, actionPath string) string {
	full := actionPath
	if modulePrefix != "" {
		full = modulePrefix + full
	}
	if appPrefix != "" {
		full = appPrefix + full
	}
	return full
}

// hoverPathDirective checks if the cursor is on a path: or prefix: line
// and shows the fully resolved route path with all prefixes combined.
func hoverPathDirective(text string, pos Position, a ast.AST) *Hover {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return nil
	}
	line := strings.TrimSpace(lines[pos.Line])

	// Find which module/action context we're in by scanning backwards
	if strings.HasPrefix(line, "path:") {
		pathVal := strings.TrimSpace(strings.TrimPrefix(line, "path:"))
		mod, act := findContextAt(lines, pos.Line)
		if act != "" && mod != "" {
			modPrefix := ""
			appPrefix := a.Prefix
			for _, m := range a.Modules {
				if m.Name == mod {
					modPrefix = m.Prefix
					break
				}
			}
			fullPath := resolveFullPath(appPrefix, modPrefix, pathVal)
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**Resolved route:** `%s`\n\napp prefix: `%s` → module prefix: `%s` → path: `%s`", fullPath, appPrefix, modPrefix, pathVal),
				},
			}
		}
	}

	if strings.HasPrefix(line, "prefix:") {
		prefixVal := strings.TrimSpace(strings.TrimPrefix(line, "prefix:"))
		mod, _ := findContextAt(lines, pos.Line)
		if mod != "" {
			appPrefix := a.Prefix
			fullPrefix := appPrefix + prefixVal
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**Resolved prefix:** `%s`\n\napp prefix: `%s` + module prefix: `%s`", fullPrefix, appPrefix, prefixVal),
				},
			}
		} else {
			// Top-level prefix
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**App prefix:** `%s`\n\nThis prefix is prepended to all module routes.", prefixVal),
				},
			}
		}
	}

	return nil
}

// hoverDefaultAnnotation shows type info when hovering over @default.
func hoverDefaultAnnotation(text string, pos Position) *Hover {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return nil
	}
	line := lines[pos.Line]
	trimmed := strings.TrimSpace(line)

	// Check if line contains @default(...)
	idx := strings.Index(trimmed, "@default(")
	if idx < 0 {
		return nil
	}

	// Extract field type from the line (fieldName: Type @default(...))
	colonIdx := strings.Index(trimmed, ":")
	if colonIdx < 0 {
		return nil
	}
	afterColon := strings.TrimSpace(trimmed[colonIdx+1:])
	// Type is everything before the first @
	atIdx := strings.Index(afterColon, "@")
	if atIdx < 0 {
		return nil
	}
	fieldType := strings.TrimSpace(afterColon[:atIdx])

	// Extract default value
	start := strings.Index(trimmed, "@default(") + len("@default(")
	end := strings.Index(trimmed[start:], ")")
	if end < 0 {
		return nil
	}
	defaultVal := trimmed[start : start+end]

	var expected string
	switch fieldType {
	case "string", "date", "datetime", "uuid", "decimal":
		expected = "quoted string (e.g. `\"value\"`)"
	case "int":
		expected = "whole number (e.g. `42`)"
	case "float":
		expected = "number (e.g. `3.14`)"
	case "bool":
		expected = "`true` or `false`"
	default:
		expected = "enum value"
	}

	return &Hover{
		Contents: MarkupContent{
			Kind:  "markdown",
			Value: fmt.Sprintf("**@default(%s)**\n\nField type: `%s`\nExpected: %s", defaultVal, fieldType, expected),
		},
	}
}

// findContextAt scans backwards from lineNum to find the enclosing module/action names.
func findContextAt(lines []string, lineNum int) (moduleName, actionName string) {
	depth := 0
	for i := lineNum; i >= 0; i-- {
		trimmed := strings.TrimSpace(lines[i])
		if trimmed == "}" {
			depth++
		}
		if trimmed == "{" || strings.HasSuffix(trimmed, "{") {
			if depth > 0 {
				depth--
				continue
			}
		}
		if strings.HasPrefix(trimmed, "action ") && actionName == "" {
			parts := strings.Fields(trimmed)
			if len(parts) >= 2 {
				actionName = strings.TrimSuffix(parts[1], "{")
			}
		}
		if strings.HasPrefix(trimmed, "module ") {
			parts := strings.Fields(trimmed)
			if len(parts) >= 2 {
				moduleName = strings.TrimSuffix(parts[1], "{")
				return
			}
		}
	}
	return
}

package lsp

import (
	"fmt"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
)

func computeHover(text string, pos Position, a ast.AST) *Hover {
	// ── Line-level hover for path:/prefix: directives ────────────────
	if h := hoverPathDirective(text, pos, a); h != nil {
		return h
	}
	// ── Line-level hover for @default annotations ────────────────────
	if h := hoverDefaultAnnotation(text, pos); h != nil {
		return h
	}

	word := wordAtPosition(text, pos)
	if word == "" {
		return nil
	}

	// Check models
	for _, m := range a.Models {
		if m.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**model %s**\n\n", m.Name))
			if m.Description != "" {
				sb.WriteString(m.Description + "\n\n")
			}
			if m.Extends != "" {
				sb.WriteString(fmt.Sprintf("extends `%s`\n\n", m.Extends))
			}
			sb.WriteString("Fields:\n")
			for _, f := range m.Fields {
				opt := ""
				if f.Optional {
					opt = "?"
				}
				typeStr := f.Type
				if len(f.UnionTypes) > 0 {
					typeStr = strings.Join(f.UnionTypes, " | ")
				}
				sb.WriteString(fmt.Sprintf("- `%s%s`: %s\n", f.Name, opt, typeStr))
			}
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}
	}

	// Check enums
	for _, en := range a.Enums {
		if en.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**enum %s**\n\n", en.Name))
			if en.Description != "" {
				sb.WriteString(en.Description + "\n\n")
			}
			sb.WriteString("Values: `" + strings.Join(en.Values, "`, `") + "`")
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}
	}

	// Check modules
	for _, mod := range a.Modules {
		if mod.Name == word {
			var sb strings.Builder
			sb.WriteString(fmt.Sprintf("**module %s**\n\n", mod.Name))
			if mod.Description != "" {
				sb.WriteString(mod.Description + "\n\n")
			}
			if mod.Prefix != "" {
				sb.WriteString(fmt.Sprintf("prefix: `%s`\n\n", mod.Prefix))
			}
			sb.WriteString(fmt.Sprintf("%d action(s)\n", len(mod.Actions)))
			for _, act := range mod.Actions {
				fullPath := resolveFullPath(a.Prefix, mod.Prefix, act.Path)
				sb.WriteString(fmt.Sprintf("- `%s %s` — %s\n", act.Method, fullPath, act.Name))
			}
			return &Hover{
				Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
			}
		}

		// Check actions
		for _, act := range mod.Actions {
			if act.Name == word {
				fullPath := resolveFullPath(a.Prefix, mod.Prefix, act.Path)
				var sb strings.Builder
				sb.WriteString(fmt.Sprintf("**action %s**\n\n", act.Name))
				if act.Description != "" {
					sb.WriteString(act.Description + "\n\n")
				}
				sb.WriteString(fmt.Sprintf("Full route: `%s %s`\n\n", act.Method, fullPath))
				if act.Input != "" {
					sb.WriteString(fmt.Sprintf("- input: `%s`\n", act.Input))
				}
				if act.Output != "" {
					out := act.Output
					if act.OutputArray {
						out += "[]"
					}
					if act.SuccessStatus > 0 {
						sb.WriteString(fmt.Sprintf("- output: `%s` → %d\n", out, act.SuccessStatus))
					} else {
						sb.WriteString(fmt.Sprintf("- output: `%s`\n", out))
					}
				}
				if act.Stream != "" {
					sb.WriteString(fmt.Sprintf("- stream: `%s`\n", act.Stream))
				}
				if len(act.Errors) > 0 {
					sb.WriteString(fmt.Sprintf("- errors: `%s`\n", strings.Join(act.Errors, "`, `")))
				}
				return &Hover{
					Contents: MarkupContent{Kind: "markdown", Value: sb.String()},
				}
			}
		}
	}

	return nil
}

func wordAtPosition(text string, pos Position) string {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return ""
	}
	line := lines[pos.Line]
	if pos.Character >= len(line) {
		return ""
	}

	// Find word boundaries
	start := pos.Character
	for start > 0 && isIdentChar(line[start-1]) {
		start--
	}
	end := pos.Character
	for end < len(line) && isIdentChar(line[end]) {
		end++
	}

	if start == end {
		return ""
	}
	return line[start:end]
}

func isIdentChar(ch byte) bool {
	return (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
		(ch >= '0' && ch <= '9') || ch == '_'
}

// resolveFullPath combines app prefix + module prefix + action path into
// the full route that will be registered at runtime.
func resolveFullPath(appPrefix, modulePrefix, actionPath string) string {
	full := actionPath
	if modulePrefix != "" {
		full = modulePrefix + full
	}
	if appPrefix != "" {
		full = appPrefix + full
	}
	return full
}

// hoverPathDirective checks if the cursor is on a path: or prefix: line
// and shows the fully resolved route path with all prefixes combined.
func hoverPathDirective(text string, pos Position, a ast.AST) *Hover {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return nil
	}
	line := strings.TrimSpace(lines[pos.Line])

	// Find which module/action context we're in by scanning backwards
	if strings.HasPrefix(line, "path:") {
		pathVal := strings.TrimSpace(strings.TrimPrefix(line, "path:"))
		mod, act := findContextAt(lines, pos.Line)
		if act != "" && mod != "" {
			modPrefix := ""
			appPrefix := a.Prefix
			for _, m := range a.Modules {
				if m.Name == mod {
					modPrefix = m.Prefix
					break
				}
			}
			fullPath := resolveFullPath(appPrefix, modPrefix, pathVal)
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**Resolved route:** `%s`\n\napp prefix: `%s` → module prefix: `%s` → path: `%s`", fullPath, appPrefix, modPrefix, pathVal),
				},
			}
		}
	}

	if strings.HasPrefix(line, "prefix:") {
		prefixVal := strings.TrimSpace(strings.TrimPrefix(line, "prefix:"))
		mod, _ := findContextAt(lines, pos.Line)
		if mod != "" {
			appPrefix := a.Prefix
			fullPrefix := appPrefix + prefixVal
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**Resolved prefix:** `%s`\n\napp prefix: `%s` + module prefix: `%s`", fullPrefix, appPrefix, prefixVal),
				},
			}
		} else {
			// Top-level prefix
			return &Hover{
				Contents: MarkupContent{
					Kind:  "markdown",
					Value: fmt.Sprintf("**App prefix:** `%s`\n\nThis prefix is prepended to all module routes.", prefixVal),
				},
			}
		}
	}

	return nil
}

// hoverDefaultAnnotation shows type info when hovering over @default.
func hoverDefaultAnnotation(text string, pos Position) *Hover {
	lines := strings.Split(text, "\n")
	if pos.Line >= len(lines) {
		return nil
	}
	line := lines[pos.Line]
	trimmed := strings.TrimSpace(line)

	// Check if line contains @default(...)
	idx := strings.Index(trimmed, "@default(")
	if idx < 0 {
		return nil
	}

	// Extract field type from the line (fieldName: Type @default(...))
	colonIdx := strings.Index(trimmed, ":")
	if colonIdx < 0 {
		return nil
	}
	afterColon := strings.TrimSpace(trimmed[colonIdx+1:])
	// Type is everything before the first @
	atIdx := strings.Index(afterColon, "@")
	if atIdx < 0 {
		return nil
	}
	fieldType := strings.TrimSpace(afterColon[:atIdx])

	// Extract default value
	start := strings.Index(trimmed, "@default(") + len("@default(")
	end := strings.Index(trimmed[start:], ")")
	if end < 0 {
		return nil
	}
	defaultVal := trimmed[start : start+end]

	var expected string
	switch fieldType {
	case "string", "date", "datetime", "uuid", "decimal":
		expected = "quoted string (e.g. `\"value\"`)"
	case "int":
		expected = "whole number (e.g. `42`)"
	case "float":
		expected = "number (e.g. `3.14`)"
	case "bool":
		expected = "`true` or `false`"
	default:
		expected = "enum value"
	}

	return &Hover{
		Contents: MarkupContent{
			Kind:  "markdown",
			Value: fmt.Sprintf("**@default(%s)**\n\nField type: `%s`\nExpected: %s", defaultVal, fieldType, expected),
		},
	}
}

// findContextAt scans backwards from lineNum to find the enclosing module/action names.
func findContextAt(lines []string, lineNum int) (moduleName, actionName string) {
	depth := 0
	for i := lineNum; i >= 0; i-- {
		trimmed := strings.TrimSpace(lines[i])
		if trimmed == "}" {
			depth++
		}
		if trimmed == "{" || strings.HasSuffix(trimmed, "{") {
			if depth > 0 {
				depth--
				continue
			}
		}
		if strings.HasPrefix(trimmed, "action ") && actionName == "" {
			parts := strings.Fields(trimmed)
			if len(parts) >= 2 {
				actionName = strings.TrimSuffix(parts[1], "{")
			}
		}
		if strings.HasPrefix(trimmed, "module ") {
			parts := strings.Fields(trimmed)
			if len(parts) >= 2 {
				moduleName = strings.TrimSuffix(parts[1], "{")
				return
			}
		}
	}
	return
}

// Package openapigen builds an OpenAPI 3.0 spec from a Veld AST.
package openapigen

import (
	"strconv"
	"strings"

	"github.com/Adhamzineldin/Veld/internal/ast"
	"github.com/Adhamzineldin/Veld/internal/emitter"
)

// BuildSpec generates a complete OpenAPI 3.0.3 spec as a nested map.
func BuildSpec(a ast.AST) map[string]interface{} {
	modelMap := make(map[string]bool, len(a.Models))
	for _, m := range a.Models {
		modelMap[m.Name] = true
	}
	enumMap := make(map[string]ast.Enum, len(a.Enums))
	for _, en := range a.Enums {
		enumMap[en.Name] = en
	}

	paths := make(map[string]interface{})
	for _, mod := range a.Modules {
		tag := mod.Name
		for _, act := range mod.Actions {
			routePath := act.Path
			if mod.Prefix != "" {
				routePath = mod.Prefix + act.Path
			}
			oaPath := emitter.ToOpenAPIPath(routePath)
			pathParams := emitter.ExtractPathParams(routePath)

			responses := make(map[string]interface{})
			successCode := "200"
			if strings.ToUpper(act.Method) == "POST" {
				successCode = "201"
			}
			if strings.ToUpper(act.Method) == "DELETE" && act.Output == "" {
				successCode = "204"
			}

			if act.Output != "" {
				outputSchema := schemaRef(act.Output, act.OutputArray, modelMap)
				responses[successCode] = map[string]interface{}{
					"description": "Success",
					"content": map[string]interface{}{
						"application/json": map[string]interface{}{
							"schema": outputSchema,
						},
					},
				}
			} else {
				responses[successCode] = map[string]interface{}{"description": "Success"}
			}

			if act.Input != "" {
				responses["400"] = map[string]interface{}{"description": "Validation error"}
			}
			if len(act.Middleware) > 0 {
				responses["401"] = map[string]interface{}{"description": "Unauthorized"}
				responses["403"] = map[string]interface{}{"description": "Forbidden"}
			}
			if len(pathParams) > 0 {
				responses["404"] = map[string]interface{}{"description": "Not found"}
			}
			responses["500"] = map[string]interface{}{"description": "Internal server error"}

			op := map[string]interface{}{
				"tags":        []string{tag},
				"operationId": mod.Name + "_" + act.Name,
				"responses":   responses,
			}
			if act.Description != "" {
				op["summary"] = act.Description
			}
			if act.Deprecated != "" {
				op["deprecated"] = true
			}
			if len(pathParams) > 0 {
				params := make([]map[string]interface{}, 0, len(pathParams))
				for _, p := range pathParams {
					params = append(params, map[string]interface{}{
						"name": p, "in": "path", "required": true,
						"schema": map[string]interface{}{"type": "string"},
					})
				}
				op["parameters"] = params
			}
			// Add header parameters when headers model is set.
			if act.Headers != "" {
				var headerFields []ast.Field
				for _, m := range a.Models {
					if m.Name == act.Headers {
						headerFields = m.Fields
						break
					}
				}
				if len(headerFields) > 0 {
					params, _ := op["parameters"].([]map[string]interface{})
					if params == nil {
						params = make([]map[string]interface{}, 0, len(headerFields))
					}
					for _, hf := range headerFields {
						params = append(params, map[string]interface{}{
							"name": hf.Name, "in": "header", "required": !hf.Optional,
							"schema": map[string]interface{}{"type": mapType(hf.Type)},
						})
					}
					op["parameters"] = params
				}
			}
			if act.Input != "" {
				op["requestBody"] = map[string]interface{}{
					"required": true,
					"content": map[string]interface{}{
						"application/json": map[string]interface{}{
							"schema": map[string]interface{}{"$ref": "#/components/schemas/" + act.Input},
						},
					},
				}
			}
			method := strings.ToLower(act.Method)
			if _, ok := paths[oaPath]; !ok {
				paths[oaPath] = make(map[string]interface{})
			}
			paths[oaPath].(map[string]interface{})[method] = op
		}
	}

	schemas := make(map[string]interface{})
	for _, m := range a.Models {
		props := make(map[string]interface{})
		var required []string
		for _, f := range m.Fields {
			props[f.Name] = fieldSchema(f, modelMap, enumMap)
			if !f.Optional {
				required = append(required, f.Name)
			}
		}
		schema := map[string]interface{}{"type": "object", "properties": props}
		if len(required) > 0 {
			schema["required"] = required
		}
		if m.Description != "" {
			schema["description"] = m.Description
		}
		if m.Extends != "" {
			schema["allOf"] = []interface{}{
				map[string]interface{}{"$ref": "#/components/schemas/" + m.Extends},
				map[string]interface{}{"type": "object", "properties": props},
			}
			delete(schema, "type")
			delete(schema, "properties")
		}
		schemas[m.Name] = schema
	}
	for _, en := range a.Enums {
		s := map[string]interface{}{"type": "string", "enum": en.Values}
		if en.Description != "" {
			s["description"] = en.Description
		}
		schemas[en.Name] = s
	}

	return map[string]interface{}{
		"openapi": "3.0.3",
		"info": map[string]interface{}{
			"title": "Veld API", "version": "1.0.0",
			"description": "Auto-generated API specification from Veld contracts",
		},
		"paths":      paths,
		"components": map[string]interface{}{"schemas": schemas},
	}
}

func schemaRef(typeName string, isArray bool, models map[string]bool) map[string]interface{} {
	var base map[string]interface{}
	if models[typeName] {
		base = map[string]interface{}{"$ref": "#/components/schemas/" + typeName}
	} else {
		base = map[string]interface{}{"type": mapType(typeName)}
		if f := mapFormat(typeName); f != "" {
			base["format"] = f
		}
	}
	if isArray {
		return map[string]interface{}{"type": "array", "items": base}
	}
	return base
}

func fieldSchema(f ast.Field, models map[string]bool, enums map[string]ast.Enum) map[string]interface{} {
	if f.IsMap {
		valSchema := map[string]interface{}{"type": mapType(f.MapValueType)}
		if models[f.MapValueType] {
			valSchema = map[string]interface{}{"$ref": "#/components/schemas/" + f.MapValueType}
		}
		return map[string]interface{}{"type": "object", "additionalProperties": valSchema}
	}
	if en, ok := enums[f.Type]; ok {
		prop := map[string]interface{}{"type": "string", "enum": en.Values}
		if f.IsArray {
			return map[string]interface{}{"type": "array", "items": prop}
		}
		return prop
	}
	if models[f.Type] {
		ref := map[string]interface{}{"$ref": "#/components/schemas/" + f.Type}
		if f.IsArray {
			return map[string]interface{}{"type": "array", "items": ref}
		}
		return ref
	}
	prop := map[string]interface{}{"type": mapType(f.Type)}
	if ft := mapFormat(f.Type); ft != "" {
		prop["format"] = ft
	}
	if f.Default != "" {
		prop["default"] = f.Default
	}
	if f.Example != "" {
		prop["example"] = f.Example
	}
	if f.Deprecated != "" {
		prop["deprecated"] = true
	}
	if f.IsArray {
		return map[string]interface{}{"type": "array", "items": prop}
	}
	return prop
}

func mapType(t string) string {
	switch t {
	case "int":
		return "integer"
	case "float":
		return "number"
	case "bool":
		return "boolean"
	case "date", "datetime", "uuid", "string", "decimal":
		return "string"
	default:
		return t
	}
}

func mapFormat(t string) string {
	switch t {
	case "date":
		return "date"
	case "datetime":
		return "date-time"
	case "uuid":
		return "uuid"
	case "int":
		return "int32"
	case "float":
		return "double"
	case "decimal":
		return "decimal"
	default:
		return ""
	}
}

